"use client";

import { forwardRef } from "react";
import { useCalendar } from "./hooks/use-calendar-context";
import { Calendar01Root } from "./parts/calendar-root";
import { CalendarToolbar } from "./parts/calendar-toolbar";
import { CalendarMiniNav } from "./parts/calendar-mini-nav";
import { CalendarMonthView } from "./parts/calendar-month-view";
import { CalendarWeekView } from "./parts/calendar-week-view";
import { CalendarDayView } from "./parts/calendar-day-view";
import { CalendarAgendaView } from "./parts/calendar-agenda-view";
import { CalendarEventInspector } from "./parts/calendar-event-inspector";
import { CalendarQuickComposer } from "./parts/calendar-quick-composer";
import {
  CalendarEventEditorOverlay,
  CalendarRenameField,
} from "./parts/calendar-edit-overlays";
import type { CalendarHandle, CalendarProps } from "./types";

/** Renders the active view (must live inside the Root to read context). */
function ActiveView() {
  const { view, availableViews } = useCalendar();
  const v = availableViews.includes(view) ? view : availableViews[0];
  switch (v) {
    case "week":
      return <CalendarWeekView />;
    case "day":
      return <CalendarDayView />;
    case "agenda":
      return <CalendarAgendaView />;
    case "month":
    default:
      return <CalendarMonthView />;
  }
}

/**
 * Calendar 01 — batteries-included assembly (Tier A). Root + toolbar + optional
 * mini-nav + the active view, gated by `show*` toggles. Contains no logic the
 * parts lack; hand-assemble `Calendar01Root` + the parts you want for a lighter
 * build.
 */
export const Calendar01 = forwardRef<CalendarHandle, CalendarProps>(
  function Calendar01(props, ref) {
    const {
      showToolbar = true,
      showMiniNav = false,
      showInspector = false,
      className,
      ...rootProps
    } = props;

    return (
      <Calendar01Root ref={ref} className={className} {...rootProps}>
        {showToolbar ? <CalendarToolbar /> : null}
        <div className="flex min-h-0 flex-1">
          {showInspector ? (
            <CalendarEventInspector className="hidden w-64 shrink-0 border-r border-border sm:flex" />
          ) : null}
          {showMiniNav ? (
            <CalendarMiniNav className="hidden border-r border-border p-2 sm:block" />
          ) : null}
          <div className="min-w-0 flex-1 overflow-hidden">
            <ActiveView />
          </div>
        </div>
        <CalendarQuickComposer />
        {/* Inline rename popup (the inspector never hosted rename). */}
        <CalendarRenameField />
        {/* Detail editor — only when the inspector isn't mounted (it hosts the
            editor inline; mounting both would double-render on `editingId`). */}
        {showInspector ? null : <CalendarEventEditorOverlay />}
      </Calendar01Root>
    );
  },
);

// Assembly (Tier A)
export { Calendar01 } from "./calendar-01";

// Headless provider + context parts (Tier B) — flat exports, never a namespace
export { Calendar01Root } from "./parts/calendar-root";
export { CalendarToolbar } from "./parts/calendar-toolbar";
export { CalendarMonthView } from "./parts/calendar-month-view";
export { CalendarWeekView } from "./parts/calendar-week-view";
export { CalendarDayView } from "./parts/calendar-day-view";
export { CalendarAgendaView } from "./parts/calendar-agenda-view";
export { CalendarMiniNav } from "./parts/calendar-mini-nav";
export { CalendarEventInspector } from "./parts/calendar-event-inspector";
export { CalendarQuickComposer } from "./parts/calendar-quick-composer";
export { CalendarEventContextMenu } from "./parts/calendar-context-menu";
export {
  CalendarEventEditorOverlay,
  CalendarRenameField,
  EventEditorPanel,
} from "./parts/calendar-edit-overlays";

// Standalone primitives (Tier C)
export {
  CalendarEventChip,
  CalendarEventBar,
  CalendarTimeBlock,
  NowIndicator,
  EventTooltip,
} from "./parts/calendar-event";
export { MonthDayCell } from "./parts/calendar-month-view";
export { TimeGrid, TimeGutter } from "./parts/calendar-time-grid";
export { AgendaRow } from "./parts/calendar-agenda-view";
export { CalendarSkeleton } from "./parts/calendar-skeleton";
export { CalendarFullCardTooltip } from "./parts/event-tooltip-full";

// Hook
export { useCalendar } from "./hooks/use-calendar-context";

// Cross-surface task clipboard (copy / cut / paste interop across task surfaces)
export {
  TASK_CLIPBOARD_KIND,
  TASK_CLIPBOARD_VERSION,
  serializeTasks,
  parseTasks,
  reassignTaskIds,
  writeTasksToClipboardEvent,
  readTasksFromClipboardEvent,
} from "./lib/clipboard";

// Public types (+ the consumed todo-rich-card data language, re-exported)
export type {
  CalendarProps,
  CalendarRootProps,
  CalendarHandle,
  CalendarView,
  WeekStart,
  EventKind,
  CalendarOccurrence,
  CalendarEventColor,
  CalendarStatusTone,
  CalendarTooltipRenderer,
  CalendarSnap,
  CalendarEditAction,
  CalendarComposerTarget,
  CalendarQuickComposerRenderer,
  TodoItem,
} from "./types";
export type { TaskClipboardEnvelope } from "./lib/clipboard";
export type {
  TodoPerson,
  TodoStatusOption,
  TodoPriorityOption,
  TodoLabelOption,
  TodoColorRamp,
  TodoPermissions,
  TodoPermissionRule,
  TodoPermissionReason,
  TodoItemAddedEvent,
  TodoItemRemovedEvent,
  TodoItemMovedEvent,
  TodoFieldEditedEvent,
  TodoStatusChangedEvent,
} from "./types";

import type { ReactNode } from "react";

/*
 * calendar-01 — the date-grid sibling of gantt-timeline-01.
 *
 * It consumes the SAME canonical TodoItem[] as the rest of the task family
 * (todo-rich-card / todo-tree / kanban-board-01 / gantt-timeline-01) and lays
 * the items onto a calendar grid (month / week / day / agenda) instead of a
 * continuous time axis. v1 is read-only; the editing surface is declared below
 * the `Editing (v0.2.0)` fence but inert in v1 (so v2 is purely additive).
 *
 * Cross-procomp reuse (mirrors gantt): the data + permission + event language
 * is IMPORTED from todo-rich-card via the same-category relative barrel and
 * RE-EXPORTED here, so a consumer importing the calendar gets the whole
 * vocabulary from one module. Rewriter-safe (same-category relative import).
 */
import type {
  TodoItem,
  TodoPerson,
  TodoStatusOption,
  TodoPriorityOption,
  TodoLabelOption,
  TodoColorRamp,
  TodoPermissions,
  TodoPermissionRule,
  TodoPermissionReason,
  TodoItemAddedEvent,
  TodoItemRemovedEvent,
  TodoItemMovedEvent,
  TodoFieldEditedEvent,
  TodoStatusChangedEvent,
} from "../todo-rich-card";

// Re-export the consumed data + editing language so a consumer importing the
// calendar gets item, option, permission, and event types without a second
// import (same-category barrel import; rewriter-safe).
export type {
  TodoItem,
  TodoPerson,
  TodoStatusOption,
  TodoPriorityOption,
  TodoLabelOption,
  TodoColorRamp,
  TodoPermissions,
  TodoPermissionRule,
  TodoPermissionReason,
  TodoItemAddedEvent,
  TodoItemRemovedEvent,
  TodoItemMovedEvent,
  TodoFieldEditedEvent,
  TodoStatusChangedEvent,
};

/* ───────── calendar enums + occurrence ───────── */

export type CalendarView = "month" | "week" | "day" | "agenda";

/** 0 = Sunday … 6 = Saturday (matches date-fns `weekStartsOn`). */
export type WeekStart = 0 | 1 | 2 | 3 | 4 | 5 | 6;

/** Semantic tone, mirrored from TodoStatusOption.tone. */
export type CalendarStatusTone = "active" | "done" | "blocked";

/** How an event is laid out. Derived (never stored on TodoItem) — see lib/classify.ts. */
export type EventKind = "all-day" | "timed" | "milestone";

export type CalendarEventColor = {
  fill: string;
  foreground: string;
  border?: string;
};

/**
 * Normalized, render-ready event — the output of lib/occurrences.ts. Exported
 * for advanced Tier-C use (like gantt's GanttRow / GanttBarGeometry).
 */
export type CalendarOccurrence = {
  /** The source item (the calendar never mutates it). */
  item: TodoItem;
  /** = item.id */
  id: string;
  kind: EventKind;
  /** Effective start, epoch ms (floating-local for date-only all-day). */
  startMs: number;
  /** Effective end, epoch ms (= startMs for a milestone). */
  endMs: number;
  /** kind !== "timed". */
  allDay: boolean;
  tone: CalendarStatusTone;
  color: CalendarEventColor;
  /** endMs < now && tone !== "done". */
  overdue: boolean;
  /** item.active === false. */
  inactive: boolean;
  /** Priority-flag color when flagged (see CalendarProps.flagPriority); else absent. */
  flagColor?: string;
  /** Unparseable date → finite-guard; rendered label-only, no geometry. */
  invalid?: boolean;
};

export type CalendarTooltipRenderer = (
  item: TodoItem,
  occ: CalendarOccurrence,
) => ReactNode;

/* ───────── editing (v0.2.0) enums + renderers ───────── */

/** Drag/resize snap granularity. Time grid snaps to the minute increment;
 *  Month always snaps to the day regardless of this value. Default "15min". */
export type CalendarSnap =
  | "minute"
  | "5min"
  | "15min"
  | "30min"
  | "hour"
  | "day"
  | "off"
  | number;

/** Edit actions; mapped onto todo-rich-card's `TodoPermissionRule` keys by
 *  `lib/edit-permissions.ts` (move/resize→drag, delete→remove, create→addChildren,
 *  editDetails→edit). Mirrors gantt's `GanttEditAction`. */
export type CalendarEditAction =
  | "move"
  | "resize"
  | "delete"
  | "create"
  | "editDetails";

/** Where the quick-composer is anchored + the seeded window. `x`/`y` are the
 *  pointer coords for floating placement (omitted for programmatic opens). */
export type CalendarComposerTarget = {
  date: Date;
  allDay: boolean;
  defaultEnd: Date;
  x?: number;
  y?: number;
};

/** Override the default quick mini-composer (title + time + "More options"). */
export type CalendarQuickComposerRenderer = (args: {
  date: Date;
  allDay: boolean;
  defaultEnd: Date;
  commit: (seed: Partial<TodoItem>) => void;
  cancel: () => void;
  openFull: () => void;
}) => ReactNode;

/* ───────── public component props ───────── */

export type CalendarProps = {
  // ── Data (identical surface to gantt / card / tree) ──
  data: TodoItem[];
  statusOptions?: TodoStatusOption[];
  priorityOptions?: TodoPriorityOption[];
  labelOptions?: TodoLabelOption[];
  /** Urgency ramp; RAMPS imported from todo-rich-card. Used only when `colorBy` is "urgency". */
  colorRamp?: TodoColorRamp;
  /** Per-status accent color (status value → CSS color). When an item's status
   *  has an entry it drives the event color — so changing status changes color. */
  statusColors?: Record<string, string>;
  /** What drives the event accent: "status" (default — by status/tone) or
   *  "urgency" (the v1 time-elapsed ramp that matches todo-rich-card + gantt). */
  colorBy?: "status" | "urgency";

  // ── Cursor: view + focus date (each controlled OR uncontrolled) ──
  defaultView?: CalendarView; // default "month"
  view?: CalendarView; // controlled
  onViewChange?: (view: CalendarView) => void;
  defaultDate?: Date; // default = now
  date?: Date; // controlled focus date
  onDateChange?: (date: Date) => void;
  /** Fires on every cursor move with the newly-visible window (lazy data fetch). */
  onRangeChange?: (range: {
    view: CalendarView;
    start: Date;
    end: Date;
  }) => void;

  // ── Calendar config ──
  weekStartsOn?: WeekStart; // default 1 (Mon)
  now?: Date | string; // SSR-stable now; client interval refreshes
  colorRefreshIntervalMs?: number; // urgency tick; default 60_000
  agendaRangeDays?: number; // default 30
  maxEventsPerCell?: number; // month overflow cap; default = height-responsive
  scrollToHour?: number; // time-grid initial scroll; default 8
  /** Classification escape hatch (layer 1 of the 3-layer rule). */
  classifyEvent?: (item: TodoItem) => EventKind | undefined;
  /** Show a small priority flag on events where this returns true (flag color =
   *  the item's `priorityOptions` color). Opt-in; e.g. `(i) => i.priority === "high"`. */
  flagPriority?: (item: TodoItem) => boolean;

  // ── Assembly toggles + layout ──
  showToolbar?: boolean; // default true (assembly only)
  showMiniNav?: boolean; // default false (assembly only)
  /** Render the selected-event inspector panel as a side column. Default false (assembly only). */
  showInspector?: boolean;
  /** Trim the toolbar view switch + assembly's mountable views. Default all four. */
  views?: CalendarView[];
  className?: string;
  "aria-label"?: string;

  // ── Read-only interactions ──
  selectedId?: string | null;
  onSelect?: (itemId: string | null) => void;
  onTaskClick?: (item: TodoItem) => void;
  /** Fires on a day click. NOTE: when `editable`, month day single-click is taken
   *  over by editing (double-click / Enter composes), so this does not fire there. */
  onDateClick?: (date: Date) => void;
  onShowMore?: (date: Date, items: TodoItem[]) => void;
  /** Override the hover tooltip; default = lightweight summary. */
  renderTooltip?: CalendarTooltipRenderer;

  // ══ Editing (v0.2.0) — ALL opt-in; default surface is the v1 read-only calendar ══
  /** Master switch. Default false → byte-identical v1 read-only behavior. */
  editable?: boolean;
  /** Full mutated forest after ANY edit; controlled consumer echoes into `data`. */
  onChange?: (data: TodoItem[]) => void;
  /** Reschedule sugar — fires alongside onChange/onFieldEdited (kept from gantt). */
  onTaskReschedule?: (next: {
    itemId: string;
    startAt: string;
    expireAt?: string;
  }) => void;
  // CRUD + field events (shapes reused verbatim from todo-rich-card)
  onItemAdded?: (event: TodoItemAddedEvent) => void;
  onItemRemoved?: (event: TodoItemRemovedEvent) => void;
  onItemMoved?: (event: TodoItemMovedEvent) => void;
  onFieldEdited?: (event: TodoFieldEditedEvent) => void;
  onStatusChanged?: (event: TodoStatusChangedEvent) => void;
  // Permissions (reused from todo-rich-card; mirrors gantt + tree)
  permissions?: TodoPermissions;
  canMoveItem?: (id: string) => boolean;
  canResizeItem?: (id: string) => boolean;
  canDeleteItem?: (id: string) => boolean;
  canCreateChild?: (id: string) => boolean;
  canEditItem?: (id: string) => boolean;
  onPermissionDenied?: (
    action: keyof TodoPermissionRule,
    itemId: string,
    reason: TodoPermissionReason,
  ) => void;
  /** Drag/resize snap granularity (time grid). Default "15min". */
  snap?: CalendarSnap;
  /** Create opens the Google-style quick mini-composer (default true when
   *  editable); false → create opens the full detail card directly. */
  quickCompose?: boolean;
  /** RESERVED — not wired by any gesture in v0.2.0. Cross-surface task transfer
   *  ships as copy/paste (the `ilinxa/task` clipboard envelope), so native HTML5
   *  external drop targets are deferred; this callback stays declared for the
   *  future opt-in but never fires today. */
  onExternalDrop?: (date: Date, allDay: boolean, data: DataTransfer) => void;
  /** Override the default quick-composer body. */
  renderQuickComposer?: CalendarQuickComposerRenderer;
};

/** Headless provider props = assembly props minus the assembly-only toggles. */
export type CalendarRootProps = Omit<
  CalendarProps,
  "showToolbar" | "showMiniNav"
> & {
  children: ReactNode;
};

/* ───────── imperative handle ───────── */

export type CalendarHandle = {
  goToDate(date: Date): void;
  goToToday(): void;
  setView(view: CalendarView): void;
  next(): void;
  prev(): void;
  getVisibleRange(): { start: Date; end: Date };
  // Editing (v0.2.0) — no-ops when `editable` is false / permission denied.
  addTask(date: Date, item?: Partial<TodoItem>): void;
  deleteTask(itemId: string): void;
  editTask(itemId: string): void;
  beginRename(itemId: string): void;
  openQuickComposer(date: Date, allDay?: boolean): void;
};

/* ───────── context (internal; constructed in the Root) ───────── */

export type CalendarContextValue = {
  // cursor
  view: CalendarView;
  focusDate: Date;
  visibleRange: { start: Date; end: Date };
  weekStartsOn: WeekStart;
  availableViews: CalendarView[];

  // data
  occurrences: CalendarOccurrence[];
  nowMs: number;

  // config
  agendaRangeDays: number;
  maxEventsPerCell?: number;
  scrollToHour: number;
  statusOptions?: TodoStatusOption[];
  priorityOptions?: TodoPriorityOption[];
  labelOptions?: TodoLabelOption[];

  // selection
  selectedId: string | null;

  // cursor actions
  setView(view: CalendarView): void;
  goToDate(date: Date): void;
  goToToday(): void;
  next(): void;
  prev(): void;
  select(id: string | null): void;

  // read-only interaction callbacks
  onTaskClick?: (item: TodoItem) => void;
  onDateClick?: (date: Date) => void;
  onShowMore?: (date: Date, items: TodoItem[]) => void;
  renderTooltip?: CalendarTooltipRenderer;

  // ── editing (v0.2.0) — always present; dispatchers no-op when !editable ──
  editable: boolean;
  snap: CalendarSnap;
  quickCompose: boolean;
  permissions?: TodoPermissions;
  /** Look up any item in the forest by id (incl. nested children). */
  getItem: (id: string) => TodoItem | undefined;
  /** Effective allow for an action on an item (false when !editable). */
  can: (action: CalendarEditAction, item: TodoItem) => boolean;
  // dispatchers (mirror gantt's use-gantt-edit surface)
  rescheduleItem: (
    id: string,
    patch: { startMs?: number; endMs?: number; allDay: boolean },
    kind: "move" | "resize",
  ) => void;
  createItem: (
    parentId: string | null,
    seed: Partial<TodoItem> | undefined,
    window: { startMs: number; endMs?: number; allDay: boolean },
    opts?: { openEditor?: boolean },
  ) => void;
  deleteItem: (id: string) => void;
  renameItemAction: (id: string, name: string) => void;
  changeStatus: (id: string, status: string) => void;
  changePriority: (id: string, priority: string) => void;
  applyEditedSubtree: (next: TodoItem) => void;
  // transient edit UI
  editingId: string | null;
  openEditor: (id: string) => void;
  closeEditor: () => void;
  renamingId: string | null;
  beginRename: (id: string) => void;
  endRename: () => void;
  composerTarget: CalendarComposerTarget | null;
  openComposer: (target: CalendarComposerTarget) => void;
  closeComposer: () => void;
  /** Live drag/resize preview geometry (mid-gesture); commit happens on release. */
  resizePreview: { id: string; startMs: number; endMs: number } | null;
  setResizePreview: (
    p: { id: string; startMs: number; endMs: number } | null,
  ) => void;
  // external drop-in + composer override
  onExternalDrop?: (date: Date, allDay: boolean, data: DataTransfer) => void;
  renderQuickComposer?: CalendarQuickComposerRenderer;
};

/**
 * Date parsing + the §7-D5 three-layer all-day/timed/milestone classification.
 * Pure; framework-free.
 */
import type { EventKind, TodoItem } from "../types";

const DATE_ONLY_RE = /^\d{4}-\d{2}-\d{2}$/;
const MS_PER_DAY = 86_400_000;

export type ParsedDate = {
  /** Epoch ms, or NaN if unparseable. */
  ms: number;
  /** True when the source was a bare YYYY-MM-DD (no time component). */
  dateOnly: boolean;
};

/**
 * Parse a TodoItem ISO date value. A bare calendar date (YYYY-MM-DD, no `T`)
 * is treated as an ALL-DAY, timezone-independent date and parsed as a FLOATING
 * LOCAL date — NOT via `Date.parse`, which per spec reads "2026-06-22" as UTC
 * midnight and renders a day early in negative-UTC offsets. Full timestamps go
 * through `Date.parse` unchanged (matching the rest of the family).
 */
export function parseDateValue(value: string | undefined): ParsedDate {
  if (!value) return { ms: NaN, dateOnly: false };
  if (DATE_ONLY_RE.test(value)) {
    const [y, m, d] = value.split("-").map(Number);
    return { ms: new Date(y, m - 1, d).getTime(), dateOnly: true };
  }
  return { ms: Date.parse(value), dateOnly: false };
}

/** Effective start (floating-local for date-only). */
export function effectiveStart(item: TodoItem): ParsedDate {
  return parseDateValue(item.startAt ?? item.setAt);
}

/**
 * Effective end. `expireAt` wins; else `start + duration`; else null (no end).
 * `ms: NaN` signals an unparseable `expireAt`.
 */
export function effectiveEnd(
  item: TodoItem,
  startMs: number,
): { ms: number | null; dateOnly: boolean } {
  if (item.expireAt) {
    const p = parseDateValue(item.expireAt);
    return { ms: p.ms, dateOnly: p.dateOnly };
  }
  if (item.duration != null) {
    return { ms: startMs + item.duration, dateOnly: false };
  }
  return { ms: null, dateOnly: false };
}

/**
 * Three-layer rule, first match wins (§7-D5):
 *   1. consumer `classifyEvent` predicate (if it returns a kind)
 *   2. no end:  date-only start ⇒ all-day (a bare date = an all-day event);
 *               otherwise ⇒ milestone (a precise instant / deadline)
 *   3. date-only start or end ⇒ all-day (Google's mechanism)
 *   4. span ≥ 1 full day ⇒ all-day
 *   5. otherwise ⇒ timed
 */
export function classify(
  item: TodoItem,
  classifyEvent?: (item: TodoItem) => EventKind | undefined,
): EventKind {
  const override = classifyEvent?.(item);
  if (override) return override;

  const start = effectiveStart(item);
  const end = effectiveEnd(item, start.ms);

  if (end.ms == null) return start.dateOnly ? "all-day" : "milestone";
  if (start.dateOnly || end.dateOnly) return "all-day";

  const span = end.ms - start.ms;
  if (Number.isFinite(span) && span >= MS_PER_DAY) return "all-day";
  return "timed";
}

/**
 * Event color resolution. The OKLCH urgency ramp is IMPORTED from todo-rich-card
 * (`RAMPS`) — not re-derived — so the calendar matches the card + gantt exactly.
 * Only the done/blocked tones are adapted (muted / destructive).
 *
 * `RAMPS` must be the FIRST `from`-import so the meta-deps audit registers the
 * todo-rich-card dependency (blackboard-01 / content-composer-01 lesson).
 */
import { RAMPS } from "../../todo-rich-card";
import type {
  CalendarEventColor,
  CalendarStatusTone,
  TodoColorRamp,
  TodoItem,
  TodoStatusOption,
} from "../types";

export function toneFor(
  item: TodoItem,
  statusOptions?: TodoStatusOption[],
): CalendarStatusTone {
  const opt = statusOptions?.find((o) => o.value === item.status);
  return opt?.tone ?? "active";
}

/** Resolve a `TodoColorRamp` (preset name | custom fn) into a callable. */
export function resolveRamp(
  ramp: TodoColorRamp | undefined,
): (t: number) => string {
  if (ramp == null) return RAMPS.default;
  if (typeof ramp === "function") return ramp;
  return RAMPS[ramp] ?? RAMPS.default;
}

/** Fraction 0..1 of the window elapsed at `nowMs`. */
export function elapsedFraction(
  startMs: number,
  endMs: number,
  nowMs: number,
): number {
  if (!Number.isFinite(startMs) || !Number.isFinite(endMs) || endMs <= startMs) {
    return 0;
  }
  const f = (nowMs - startMs) / (endMs - startMs);
  return f < 0 ? 0 : f > 1 ? 1 : f;
}

/**
 * Resolve the accent color for an event. Precedence:
 *   item.borderColor override → that color (skips the engine)
 *   statusColor (statusColors[item.status]) → that color (status-driven)
 *   tone "done"    → muted-foreground
 *   tone "blocked" → destructive
 *   colorBy "urgency" → time-elapsed ramp (the v1 behavior, matches card + gantt)
 *   otherwise (status mode, active, no explicit color) → primary
 *
 * The accent is the chip/block border + text; the surface tints it (color-mix)
 * for the background — same accent, light fill. Default `colorBy` is "status",
 * so changing an item's status changes its color (use "urgency" for the ramp).
 */
export function eventColor(
  item: TodoItem,
  tone: CalendarStatusTone,
  startMs: number,
  endMs: number,
  nowMs: number,
  ramp: (t: number) => string,
  statusColor?: string,
  colorBy: "status" | "urgency" = "status",
): CalendarEventColor {
  let accent: string;
  if (item.borderColor) accent = item.borderColor;
  else if (statusColor) accent = statusColor;
  else if (tone === "done") accent = "var(--muted-foreground)";
  else if (tone === "blocked") accent = "var(--destructive)";
  else if (colorBy === "urgency") accent = ramp(elapsedFraction(startMs, endMs, nowMs));
  else accent = "var(--primary)";
  return { fill: accent, foreground: accent, border: accent };
}

/**
 * Calendar date math — pure, framework-free, all via date-fns (DST-correct by
 * construction). Maps the cursor (view + focus date) to the visible range and
 * the per-view day grids.
 */
import {
  addDays,
  addMonths,
  addWeeks,
  eachDayOfInterval,
  endOfMonth,
  endOfWeek,
  startOfDay,
  startOfMonth,
  startOfWeek,
} from "date-fns";
import type { CalendarView, WeekStart } from "../types";

/** The inclusive-start / exclusive-ish-end window the active view covers. */
export function visibleRange(
  view: CalendarView,
  focusDate: Date,
  weekStartsOn: WeekStart,
  agendaRangeDays: number,
): { start: Date; end: Date } {
  switch (view) {
    case "month": {
      return {
        start: startOfWeek(startOfMonth(focusDate), { weekStartsOn }),
        end: endOfWeek(endOfMonth(focusDate), { weekStartsOn }),
      };
    }
    case "week": {
      return {
        start: startOfWeek(focusDate, { weekStartsOn }),
        end: endOfWeek(focusDate, { weekStartsOn }),
      };
    }
    case "day": {
      const s = startOfDay(focusDate);
      return { start: s, end: addDays(s, 1) };
    }
    case "agenda": {
      const s = startOfDay(focusDate);
      return { start: s, end: addDays(s, Math.max(1, agendaRangeDays)) };
    }
  }
}

/** Full weeks (5–6 rows × 7 days) covering the focus month. */
export function monthGrid(focusDate: Date, weekStartsOn: WeekStart): Date[][] {
  const { start, end } = visibleRange("month", focusDate, weekStartsOn, 0);
  const days = eachDayOfInterval({ start, end });
  const weeks: Date[][] = [];
  for (let i = 0; i < days.length; i += 7) weeks.push(days.slice(i, i + 7));
  return weeks;
}

/** The 7 day columns of the focus week. */
export function weekColumns(focusDate: Date, weekStartsOn: WeekStart): Date[] {
  const s = startOfWeek(focusDate, { weekStartsOn });
  return Array.from({ length: 7 }, (_, i) => addDays(s, i));
}

/** The consecutive days an agenda window spans (for day grouping). */
export function agendaDays(focusDate: Date, agendaRangeDays: number): Date[] {
  const s = startOfDay(focusDate);
  return Array.from({ length: Math.max(1, agendaRangeDays) }, (_, i) =>
    addDays(s, i),
  );
}

/** Step the focus date by one view-relative period. `dir` = +1 / −1. */
export function stepDate(
  view: CalendarView,
  focusDate: Date,
  dir: number,
  agendaRangeDays: number,
): Date {
  switch (view) {
    case "month":
      return addMonths(focusDate, dir);
    case "week":
      return addWeeks(focusDate, dir);
    case "day":
      return addDays(focusDate, dir);
    case "agenda":
      return addDays(focusDate, dir * Math.max(1, agendaRangeDays));
  }
}

/** 0..23 — the hour rows of a time-grid. */
export const HOURS: number[] = Array.from({ length: 24 }, (_, h) => h);

/**
 * TodoItem[] → CalendarOccurrence[] — the single normalization pass.
 * Pure; framework-free. Flattens `children` (every dated item renders; no WBS
 * rollup — D10), computes the effective window with finite guards (never a NaN
 * geometry / `toISOString` throw — gantt v0.3.1 G2 lesson), classifies, and
 * resolves color via the shared engine.
 */
import { classify, effectiveEnd, effectiveStart } from "./classify";
import { eventColor, resolveRamp, toneFor } from "./color";
import type {
  CalendarOccurrence,
  EventKind,
  TodoColorRamp,
  TodoItem,
  TodoPriorityOption,
  TodoStatusOption,
} from "../types";

export type OccurrenceContext = {
  nowMs: number;
  classifyEvent?: (item: TodoItem) => EventKind | undefined;
  statusOptions?: TodoStatusOption[];
  priorityOptions?: TodoPriorityOption[];
  colorRamp?: TodoColorRamp;
  /** Per-status accent color; drives the event color in "status" mode. */
  statusColors?: Record<string, string>;
  /** "status" (default) or "urgency" (time ramp). */
  colorBy?: "status" | "urgency";
  /** Predicate → events that show a priority flag. */
  flagPriority?: (item: TodoItem) => boolean;
};

export function toOccurrences(
  data: TodoItem[],
  ctx: OccurrenceContext,
): CalendarOccurrence[] {
  const ramp = resolveRamp(ctx.colorRamp);
  const out: CalendarOccurrence[] = [];

  const walk = (item: TodoItem) => {
    const kind = classify(item, ctx.classifyEvent);
    const start = effectiveStart(item);
    const end = effectiveEnd(item, start.ms);

    const startMs = start.ms;
    const rawEnd = end.ms == null ? startMs : end.ms; // no end ⇒ point
    const invalid =
      !Number.isFinite(startMs) || (end.ms != null && !Number.isFinite(end.ms));

    // Finite guard: never emit a NaN geometry.
    let endMs = Number.isFinite(rawEnd) ? rawEnd : startMs;
    if (Number.isFinite(startMs) && Number.isFinite(endMs) && endMs < startMs) {
      endMs = startMs;
    }

    const tone = toneFor(item, ctx.statusOptions);
    const overdue =
      Number.isFinite(endMs) && endMs < ctx.nowMs && tone !== "done";
    const statusColor = ctx.statusColors?.[item.status];
    const color = eventColor(
      item,
      tone,
      startMs,
      endMs,
      ctx.nowMs,
      ramp,
      statusColor,
      ctx.colorBy,
    );
    const flagColor = ctx.flagPriority?.(item)
      ? (ctx.priorityOptions?.find((o) => o.value === item.priority)?.color ??
        "var(--destructive)")
      : undefined;

    out.push({
      item,
      id: item.id,
      kind,
      startMs,
      endMs,
      allDay: kind !== "timed",
      tone,
      color,
      overdue,
      inactive: item.active === false,
      flagColor,
      invalid: invalid || undefined,
    });

    item.children?.forEach(walk);
  };

  data.forEach(walk);
  return out;
}

/** Occurrences whose covered span intersects [startMs, endMs). */
export function occurrencesInRange(
  occ: CalendarOccurrence[],
  startMs: number,
  endMs: number,
): CalendarOccurrence[] {
  return occ.filter(
    (o) => !o.invalid && o.endMs >= startMs && o.startMs < endMs,
  );
}

/**
 * Month-grid layout — pure. Lays a week's occurrences into horizontal lanes:
 * multi-day events become spanning bar segments (clipped per week row, with
 * continuation flags), single-day events occupy one column. Overflow past the
 * lane cap becomes a per-day "+N more" count.
 */
import { addDays, differenceInCalendarDays, startOfDay } from "date-fns";
import type { CalendarOccurrence } from "../types";

/**
 * First/last covered calendar day (local). All-day end is EXCLUSIVE at local
 * midnight (iCal / Google semantics): an event 00:00 Mon → 00:00 Wed covers
 * Mon + Tue.
 */
export function coveredDays(occ: CalendarOccurrence): {
  firstMs: number;
  lastMs: number;
} {
  const first = startOfDay(occ.startMs).getTime();
  let lastDay = startOfDay(occ.endMs);
  if (occ.endMs === lastDay.getTime() && lastDay.getTime() > first) {
    lastDay = addDays(lastDay, -1); // exclusive midnight end
  }
  return { firstMs: first, lastMs: Math.max(first, lastDay.getTime()) };
}

export type MonthSegment = {
  occ: CalendarOccurrence;
  lane: number;
  startCol: number; // 0..6 within the week
  endCol: number; // 0..6
  continuesLeft: boolean; // clipped at the week's left edge
  continuesRight: boolean; // clipped at the week's right edge
  spanning: boolean; // endCol > startCol → bar, else chip
};

export type MonthWeekLayout = {
  segments: MonthSegment[]; // lane < cap
  overflow: number[]; // hidden-count per day-column (length 7)
  laneCount: number; // lanes actually rendered (≤ cap)
};

/**
 * Lay a run of `startOfDay` dates into ≤ `cap` lanes. Used by the month grid
 * (7-day weeks) AND the week/day all-day band (1–7 columns) — hence generalized
 * to `weekDays.length` rather than a hardcoded 7 (F-03).
 */
export function layoutMonthWeek(
  weekDays: Date[],
  occurrences: CalendarOccurrence[],
  cap: number,
): MonthWeekLayout {
  const lastCol = weekDays.length - 1;
  const weekStart = startOfDay(weekDays[0]).getTime();
  const weekEnd = startOfDay(weekDays[lastCol]).getTime();

  type Placed = { occ: CalendarOccurrence; startCol: number; endCol: number };
  const placed: Placed[] = [];
  for (const occ of occurrences) {
    if (occ.invalid) continue;
    const { firstMs, lastMs } = coveredDays(occ);
    if (lastMs < weekStart || firstMs > weekEnd) continue;
    const startCol = Math.max(
      0,
      differenceInCalendarDays(new Date(Math.max(firstMs, weekStart)), weekDays[0]),
    );
    const endCol = Math.min(
      lastCol,
      differenceInCalendarDays(new Date(Math.min(lastMs, weekEnd)), weekDays[0]),
    );
    placed.push({ occ, startCol, endCol });
  }

  // All-day / multi-day first (earlier start, then longer span), timed after.
  placed.sort((a, b) => {
    const am = a.occ.allDay ? 0 : 1;
    const bm = b.occ.allDay ? 0 : 1;
    if (am !== bm) return am - bm;
    if (a.startCol !== b.startCol) return a.startCol - b.startCol;
    return b.endCol - b.startCol - (a.endCol - a.startCol);
  });

  const laneOccupancy: boolean[][] = []; // [lane][col]
  const overflow = new Array(weekDays.length).fill(0);
  const segments: MonthSegment[] = [];
  let laneCount = 0;

  for (const p of placed) {
    let lane = 0;
    for (;;) {
      if (!laneOccupancy[lane])
        laneOccupancy[lane] = new Array(weekDays.length).fill(false);
      let free = true;
      for (let c = p.startCol; c <= p.endCol; c++) {
        if (laneOccupancy[lane][c]) {
          free = false;
          break;
        }
      }
      if (free) break;
      lane++;
    }
    for (let c = p.startCol; c <= p.endCol; c++) laneOccupancy[lane][c] = true;

    if (lane >= cap) {
      for (let c = p.startCol; c <= p.endCol; c++) overflow[c]++;
      continue;
    }
    laneCount = Math.max(laneCount, lane + 1);
    const { firstMs, lastMs } = coveredDays(p.occ);
    segments.push({
      occ: p.occ,
      lane,
      startCol: p.startCol,
      endCol: p.endCol,
      continuesLeft: firstMs < weekStart,
      continuesRight: lastMs > weekEnd,
      spanning: p.endCol > p.startCol,
    });
  }

  return { segments, overflow, laneCount };
}

/** Every occurrence covering a given day (for the "+N more" popover list). */
export function occurrencesOnDay(
  occ: CalendarOccurrence[],
  day: Date,
): CalendarOccurrence[] {
  const dayStart = startOfDay(day).getTime();
  return occ.filter((o) => {
    if (o.invalid) return false;
    const { firstMs, lastMs } = coveredDays(o);
    return dayStart >= firstMs && dayStart <= lastMs;
  });
}

/**
 * Week/Day time-grid overlap packing — pure. Classic greedy interval-graph
 * column assignment: overlapping timed events split into side-by-side lanes;
 * each cluster reports its lane count so blocks can size to `1 / laneCount`.
 */
import type { CalendarOccurrence } from "../types";

export type PackedBlock = {
  occ: CalendarOccurrence;
  lane: number; // 0-based column within its cluster
  laneCount: number; // columns in the cluster (block width = 1 / laneCount)
};

export function packLanes(timed: CalendarOccurrence[]): PackedBlock[] {
  const sorted = [...timed].sort(
    (a, b) => a.startMs - b.startMs || a.endMs - b.endMs,
  );

  const out: PackedBlock[] = [];
  let cluster: { occ: CalendarOccurrence; lane: number }[] = [];
  let clusterEnd = -Infinity;
  const laneEnds: number[] = []; // end ms per active lane

  const flush = () => {
    if (!cluster.length) return;
    const laneCount = Math.max(1, ...cluster.map((c) => c.lane + 1));
    for (const c of cluster) out.push({ occ: c.occ, lane: c.lane, laneCount });
    cluster = [];
    laneEnds.length = 0;
  };

  for (const occ of sorted) {
    // A gap with no overlap closes the current cluster.
    if (cluster.length && occ.startMs >= clusterEnd) flush();

    let lane = laneEnds.findIndex((end) => end <= occ.startMs);
    if (lane === -1) {
      lane = laneEnds.length;
      laneEnds.push(occ.endMs);
    } else {
      laneEnds[lane] = occ.endMs;
    }
    cluster.push({ occ, lane });
    clusterEnd = Math.max(clusterEnd, occ.endMs);
  }
  flush();
  return out;
}

/** Vertical placement of a timed block within a day column, as 0..1 fractions. */
export function blockOffsets(
  occ: CalendarOccurrence,
  dayStartMs: number,
): { top: number; height: number } {
  const dayMs = 86_400_000;
  const top = Math.max(0, (occ.startMs - dayStartMs) / dayMs);
  const rawH = (occ.endMs - occ.startMs) / dayMs;
  // Minimum height so a very short event is still tappable.
  const height = Math.min(1 - top, Math.max(rawH, 0.02));
  return { top, height };
}

/**
 * Pure forest mutations over `TodoItem[]` — the editing layer (v0.2.0).
 *
 * The array analogue of todo-rich-card's reducer mutations and the date-grid
 * sibling of gantt's `lib/edit-mutations.ts`: every function returns a NEW forest
 * with structural sharing and NEVER mutates in place, so the controlled consumer
 * can diff/echo and stack undo for free. Framework-free; Vitest-ready. Hierarchy
 * is nested `children` (no parentId on TodoItem), so the index here is what
 * callers use to locate a splice point.
 *
 * Calendar-specific delta vs gantt: `setWindow` is **all-day aware**. Where gantt
 * always serializes via `new Date(ms).toISOString()`, the calendar must write a
 * bare `YYYY-MM-DD` (from LOCAL fields) for all-day items so the value round-trips
 * through `classify.ts`'s floating-local `parseDateValue` without the UTC
 * off-by-one. `formatDateValue` is the inverse of `parseDateValue`.
 */

import type { CalendarSnap, TodoItem } from "../types";
import { parseDateValue } from "./classify";

/** Minimum timed span (ms) so a resize/drag can't collapse a block to zero. */
export const MIN_DURATION_MS = 60_000;

/** Snap increment (ms) for a `CalendarSnap`. `"off"` → 0 (no snap). */
export function snapStepMs(snap: CalendarSnap): number {
  if (typeof snap === "number") return Math.max(0, snap);
  switch (snap) {
    case "off":
      return 0;
    case "minute":
      return 60_000;
    case "5min":
      return 300_000;
    case "15min":
      return 900_000;
    case "30min":
      return 1_800_000;
    case "hour":
      return 3_600_000;
    case "day":
      return 86_400_000;
    default:
      return 900_000; // "15min" fallback
  }
}

/** Round `ms` to the nearest `step` relative to `originMs` (e.g. the day start). */
export function snapToStep(ms: number, originMs: number, step: number): number {
  if (step <= 0 || !Number.isFinite(ms)) return ms;
  return originMs + Math.round((ms - originMs) / step) * step;
}

/**
 * Inverse of `classify.ts`'s `parseDateValue`:
 *   - all-day  → bare `YYYY-MM-DD` built from LOCAL Y/M/D (NEVER `toISOString`,
 *                which is UTC and renders a day early in negative-UTC offsets).
 *   - timed    → full ISO timestamp.
 * Returns "" for a non-finite ms so callers never emit `new Date(NaN).toISOString()`.
 */
export function formatDateValue(ms: number, allDay: boolean): string {
  if (!Number.isFinite(ms)) return "";
  if (allDay) {
    const d = new Date(ms);
    const p = (n: number) => String(n).padStart(2, "0");
    return `${d.getFullYear()}-${p(d.getMonth() + 1)}-${p(d.getDate())}`;
  }
  return new Date(ms).toISOString();
}

export type ForestNodeInfo = {
  item: TodoItem;
  parentId: string | null;
  index: number;
  /** 1 = root. */
  level: number;
};

/** Flat `id → { item, parentId, index, level }` over the whole forest. */
export function buildIndex(data: TodoItem[]): Map<string, ForestNodeInfo> {
  const map = new Map<string, ForestNodeInfo>();
  const walk = (items: TodoItem[], parentId: string | null, level: number) => {
    items.forEach((item, index) => {
      map.set(item.id, { item, parentId, index, level });
      if (item.children?.length) walk(item.children, item.id, level + 1);
    });
  };
  walk(data, null, 1);
  return map;
}

/** Replace the matching item via `fn`; returns the same ref when nothing changed. */
function replace(
  data: TodoItem[],
  id: string,
  fn: (item: TodoItem) => TodoItem,
): TodoItem[] {
  let changed = false;
  const next = data.map((item) => {
    if (item.id === id) {
      changed = true;
      return fn(item);
    }
    if (item.children?.length) {
      const kids = replace(item.children, id, fn);
      if (kids !== item.children) {
        changed = true;
        return { ...item, children: kids };
      }
    }
    return item;
  });
  return changed ? next : data;
}

export function renameItem(
  data: TodoItem[],
  id: string,
  name: string,
): TodoItem[] {
  return replace(data, id, (item) => ({ ...item, name }));
}

/**
 * Apply a calendar window patch (reschedule / resize / all-day⇄timed convert).
 *
 * Takes epoch **ms + an `allDay` flag** (not ISO strings — the geometry layer
 * hands it numbers and the formatter decides the serialization). The calendar
 * canonicalizes to a `startAt` + `expireAt` pair: when an `endMs` is written, a
 * pre-existing `duration` is dropped (an explicit end is clearer than a duration
 * for a calendar event, and avoids a stale duration shadowing the new expireAt).
 * Enforces `end ≥ start + MIN_DURATION_MS` for timed only (all-day spans are
 * day-quantized and need no ms floor). Non-finite ms leave the field untouched
 * rather than emitting `new Date(NaN).toISOString()`.
 */
export function setWindow(
  data: TodoItem[],
  id: string,
  patch: { startMs?: number; endMs?: number; allDay: boolean },
): TodoItem[] {
  return replace(data, id, (item) => {
    const next: TodoItem = { ...item };
    if (patch.startMs != null && Number.isFinite(patch.startMs)) {
      next.startAt = formatDateValue(patch.startMs, patch.allDay);
    }
    if (patch.endMs != null) {
      const startMs =
        patch.startMs != null && Number.isFinite(patch.startMs)
          ? patch.startMs
          : parseDateValue(next.startAt ?? next.setAt).ms;
      let endMs = patch.endMs;
      if (
        !patch.allDay &&
        Number.isFinite(startMs) &&
        Number.isFinite(endMs) &&
        endMs < startMs + MIN_DURATION_MS
      ) {
        endMs = startMs + MIN_DURATION_MS;
      }
      if (Number.isFinite(endMs)) {
        next.expireAt = formatDateValue(endMs, patch.allDay);
        if (next.duration != null) delete next.duration; // canonicalize to expireAt-driven
      }
    }
    return next;
  });
}

/** True when `maybeAncestorId` is an ancestor of `id` (circular-drop guard). */
export function isAncestor(
  data: TodoItem[],
  maybeAncestorId: string,
  id: string,
): boolean {
  const idx = buildIndex(data);
  let cur = idx.get(id)?.parentId ?? null;
  while (cur != null) {
    if (cur === maybeAncestorId) return true;
    cur = idx.get(cur)?.parentId ?? null;
  }
  return false;
}

/** Insert `item` under `parentId` (null = root) at `index` (default = append). */
export function addItem(
  data: TodoItem[],
  parentId: string | null,
  item: TodoItem,
  index?: number,
): TodoItem[] {
  if (parentId == null) {
    const next = [...data];
    next.splice(index ?? next.length, 0, item);
    return next;
  }
  return replace(data, parentId, (parent) => {
    const kids = parent.children ? [...parent.children] : [];
    kids.splice(index ?? kids.length, 0, item);
    return { ...parent, children: kids };
  });
}

/** Remove an item; returns the new forest + the removed subtree + its old parent. */
export function removeItem(
  data: TodoItem[],
  id: string,
): { next: TodoItem[]; removed: TodoItem | null; parentId: string | null } {
  const info = buildIndex(data).get(id);
  if (!info) return { next: data, removed: null, parentId: null };
  const prune = (items: TodoItem[]): TodoItem[] =>
    items
      .filter((it) => it.id !== id)
      .map((it) =>
        it.children?.length ? { ...it, children: prune(it.children) } : it,
      );
  return { next: prune(data), removed: info.item, parentId: info.parentId };
}

/**
 * Move an item to `newParentId` (null = root) at `newIndex`. The caller guards
 * circular drops (`isAncestor`); `newIndex` is interpreted against the target
 * parent's children AFTER the source has been removed (todo-tree semantics).
 * Reserved for the v0.2.0 "drop-onto-an-event-to-nest" path (not wired by any
 * gesture this version — calendar's "move" is reschedule, not reparent).
 */
export function moveItem(
  data: TodoItem[],
  id: string,
  newParentId: string | null,
  newIndex: number,
): TodoItem[] {
  const { next: pruned, removed } = removeItem(data, id);
  if (!removed) return data;
  return addItem(pruned, newParentId, removed, newIndex);
}

/**
 * Calendar edit-permission resolver. Mirrors gantt's `lib/edit-permissions.ts`
 * (itself mirroring todo-tree): maps the calendar's edit actions onto
 * todo-rich-card's `TodoPermissionRule` keys and resolves against the shared
 * `TodoPermissions` matrix (+ `item.locked`). One matrix shape across card / tree
 * / gantt / calendar = one mental model for consumers. Framework-free; Vitest-ready.
 */

import type {
  CalendarEditAction,
  TodoItem,
  TodoPermissionRule,
  TodoPermissions,
} from "../types";

/** Calendar actions piggy-back on the most natural existing rule key. */
const ACTION_TO_RULE: Record<CalendarEditAction, keyof TodoPermissionRule> = {
  move: "drag",
  resize: "drag",
  delete: "remove",
  create: "addChildren",
  editDetails: "edit",
};

/**
 * Effective allow/deny for one action on `item` at `level` (1 = root). Hard lock
 * (`item.locked`) denies everything. Lookup order byItem → byLevel → default,
 * then a `true` fallback; `inherit !== false` ascends on undefined keys.
 */
export function evalCalendarPermission(
  permissions: TodoPermissions | undefined,
  action: CalendarEditAction,
  item: TodoItem,
  level: number,
): boolean {
  if (item.locked) return false;
  if (!permissions) return true;

  const key = ACTION_TO_RULE[action];
  const inherit = permissions.inherit !== false;

  const byItem = permissions.byItem?.[item.id]?.[key];
  if (byItem !== undefined) return byItem;
  if (!inherit && permissions.byItem?.[item.id]) return true;

  const byLevel = permissions.byLevel?.[level]?.[key];
  if (byLevel !== undefined) return byLevel;
  if (!inherit && permissions.byLevel?.[level]) return true;

  const def = permissions.default?.[key];
  if (def !== undefined) return def;

  return true;
}

/**
 * Cross-surface task clipboard (v0.2.0). A small, framework-free envelope so any
 * task-family surface (calendar / gantt / kanban / tree / rich-card) can copy &
 * paste `TodoItem`s through the OS clipboard — they all speak the same canonical
 * shape, so a copy here pastes there and vice-versa.
 *
 * The payload rides in `text/plain` (universally portable; custom MIME types are
 * unreliable across browsers/apps). Foreign clipboard text parses to `null` so a
 * normal paste falls through untouched. Calendar is the first adopter; the intent
 * is to hoist this verbatim into todo-rich-card (the shared vocabulary every task
 * surface already imports) and wire the others.
 *
 * Pure + framework-free (Vitest-ready): `serialize`/`parse`/`reassignTaskIds` are
 * deterministic given their inputs; the two `*Event` adapters are the only DOM
 * touch-points and are called from client clipboard handlers.
 */

import type { TodoItem } from "../types";

/** Envelope sentinel — a foreign payload (plain text, other app's JSON) lacks it. */
export const TASK_CLIPBOARD_KIND = "ilinxa/task";
export const TASK_CLIPBOARD_VERSION = 1;

export interface TaskClipboardEnvelope {
  kind: typeof TASK_CLIPBOARD_KIND;
  version: number;
  /** Provenance hint (e.g. "calendar-01"); informational only. */
  source?: string;
  items: TodoItem[];
}

/** Fresh id (crypto-guarded fallback) — mirrors `use-calendar-edit`'s `freshId`. */
function freshId(): string {
  if (typeof crypto !== "undefined" && "randomUUID" in crypto) {
    return `cal-${crypto.randomUUID()}`;
  }
  return `cal-${Math.random().toString(36).slice(2)}-${Math.random().toString(36).slice(2)}`;
}

/**
 * Deep-clone a `TodoItem` subtree with fresh ids so a paste can never collide
 * with the source (or with an item pasted twice). Local mirror of
 * `todo-rich-card/lib/normalize.ts#reassignIds` — that one isn't barrel-exported,
 * and registry rules forbid reaching past the barrel.
 */
export function reassignTaskIds(item: TodoItem): TodoItem {
  return {
    ...item,
    id: freshId(),
    children: item.children?.map(reassignTaskIds),
  };
}

/** Serialize tasks to the clipboard text payload (JSON envelope). */
export function serializeTasks(items: TodoItem[], source?: string): string {
  const envelope: TaskClipboardEnvelope = {
    kind: TASK_CLIPBOARD_KIND,
    version: TASK_CLIPBOARD_VERSION,
    source,
    items,
  };
  return JSON.stringify(envelope);
}

/** Parse a clipboard text payload back to tasks; `null` if it isn't our envelope. */
export function parseTasks(text: string | null | undefined): TodoItem[] | null {
  if (!text) return null;
  try {
    const parsed = JSON.parse(text) as Partial<TaskClipboardEnvelope>;
    if (
      parsed &&
      parsed.kind === TASK_CLIPBOARD_KIND &&
      Array.isArray(parsed.items) &&
      parsed.items.length > 0
    ) {
      return parsed.items as TodoItem[];
    }
  } catch {
    // Not JSON / not ours — let the native paste proceed.
  }
  return null;
}

/** Write tasks onto a clipboard event (the `copy`/`cut` handlers). */
export function writeTasksToClipboardEvent(
  e: ClipboardEvent,
  items: TodoItem[],
  source?: string,
): void {
  e.clipboardData?.setData("text/plain", serializeTasks(items, source));
}

/** Read tasks from a clipboard event (the `paste` handler); `null` if foreign. */
export function readTasksFromClipboardEvent(
  e: ClipboardEvent,
): TodoItem[] | null {
  return parseTasks(e.clipboardData?.getData("text/plain"));
}

