 * converts): a focused day-cell → that day, all-day; a focused event → its
 * day + all-day-ness; otherwise the current focus date (timed in week/day at
 * `scrollToHour`, else all-day). Duration is carried from the copied item.
 */
function resolvePasteWindow(
  items: TodoItem[],
  opts: {
    activeEl: Element | null;
    occurrences: CalendarOccurrence[];
    view: CalendarView;
    focusDate: Date;
    scrollToHour: number;
  },
): { startMs: number; endMs?: number; allDay: boolean } {
  const { activeEl, occurrences, view, focusDate, scrollToHour } = opts;
  const dur = itemDurationMs(items[0]);
  const dayEl = activeEl?.closest?.("[data-day-ms]") as HTMLElement | null;
  if (dayEl) {
    const startMs = Number(dayEl.getAttribute("data-day-ms"));
    return { startMs, endMs: dur > 0 ? startMs + dur : undefined, allDay: true };
  }
  const occEl = activeEl?.closest?.("[data-occ-id]") as HTMLElement | null;
  if (occEl) {
    const occ = occurrences.find(
      (o) => o.id === occEl.getAttribute("data-occ-id"),
    );
    if (occ) {
      const span = occ.endMs > occ.startMs ? occ.endMs - occ.startMs : 0;
      const length = dur > 0 ? dur : span;
      return {
        startMs: occ.startMs,
        endMs: length > 0 ? occ.startMs + length : undefined,
        allDay: occ.allDay,
      };
    }
  }
  const base = startOfDay(focusDate).getTime();
  if (view === "week" || view === "day") {
    const startMs = base + Math.max(0, Math.min(23, scrollToHour)) * 3_600_000;
    return {
      startMs,
      endMs: dur > 0 ? startMs + dur : startMs + 3_600_000,
      allDay: false,
    };
  }
  return { startMs: base, endMs: dur > 0 ? base + dur : undefined, allDay: true };
}

/**
 * Headless provider (Tier B). Owns ALL state — the cursor (view + focus date),
 * selection, the memoized occurrences, the now-tick — plus the context and the
 * imperative handle. Renders `children`. No data state of its own (controlled,
 * family invariant); the v2 editing block is inert here.
 */
export const Calendar01Root = forwardRef<CalendarHandle, CalendarRootProps>(
  function Calendar01Root(props, ref) {
    const {
      data,
      statusOptions,
      priorityOptions,
      labelOptions,
      colorRamp,
      statusColors,
      colorBy,
      flagPriority,
      classifyEvent,
      now,
      colorRefreshIntervalMs = 60_000,
      agendaRangeDays = 30,
      maxEventsPerCell,
      scrollToHour = 8,
      weekStartsOn = 1,
      views,
      selectedId: selectedIdProp,
      onSelect,
      onTaskClick,
      onDateClick,
      onShowMore,
      onRangeChange,
      renderTooltip,
      // editing (v0.2.0)
      editable = false,
      snap = "15min",
      quickCompose = true,
      onChange,
      onTaskReschedule,
      onItemAdded,
      onItemRemoved,
      onItemMoved,
      onFieldEdited,
      onStatusChanged,
      permissions,
      canMoveItem,
      canResizeItem,
      canDeleteItem,
      canCreateChild,
      canEditItem,
      onPermissionDenied,
      onExternalDrop,
      renderQuickComposer,
      className,
      children,
    } = props;

    const availableViews = useMemo(
      () => (views && views.length ? views : ALL_VIEWS),
      [views],
    );

    const cursor = useCalendarCursor({
      defaultView: props.defaultView,
      view: props.view,
      onViewChange: props.onViewChange,
      defaultDate: props.defaultDate,
      date: props.date,
      onDateChange: props.onDateChange,
      now,
      agendaRangeDays,
    });
    const { view, focusDate, setView, goToDate, goToToday, next, prev } = cursor;

    const nowMs = useNowTick(now, colorRefreshIntervalMs);

    const occurrences = useMemo(
      () =>
        toOccurrences(data, {
          nowMs,
          classifyEvent,
          statusOptions,
          priorityOptions,
          colorRamp,
          statusColors,
          colorBy,
          flagPriority,
        }),
      [
        data,
        nowMs,
        classifyEvent,
        statusOptions,
        priorityOptions,
        colorRamp,
        statusColors,
        colorBy,
        flagPriority,
      ],
    );

    const visibleRange = useMemo(
      () => computeVisibleRange(view, focusDate, weekStartsOn, agendaRangeDays),
      [view, focusDate, weekStartsOn, agendaRangeDays],
    );

    // Selection — controlled (incl. null) or internal.
    const [internalSelected, setInternalSelected] = useState<string | null>(
      null,
    );
    const selectionControlled = selectedIdProp !== undefined;
    const selectedId = selectionControlled
      ? (selectedIdProp ?? null)
      : internalSelected;
    const select = useCallback(
      (id: string | null) => {
        if (!selectionControlled) setInternalSelected(id);
        onSelect?.(id);
      },
      [selectionControlled, onSelect],
    );

    // ── editing (v0.2.0) — the dispatcher chokepoints; all no-op when !editable ──
    const edit = useCalendarEdit({
      data,
      editable,
      snap,
      statusOptions,
      select,
      onChange,
      onTaskReschedule,
      onItemAdded,
      onItemRemoved,
      onItemMoved,
      onFieldEdited,
      onStatusChanged,
      permissions,
      canMoveItem,
      canResizeItem,
      canDeleteItem,
      canCreateChild,
      canEditItem,
      onPermissionDenied,
    });
    const {
      can,
      getItem,
      rescheduleItem,
      createItem,
      pasteTasks,
      deleteItem,
      renameItemAction,
      changeStatus,
      changePriority,
      applyEditedSubtree,
      editingId,
      openEditor,
      closeEditor,
      renamingId,
      beginRename,
      endRename,
      composerTarget,
      openComposer,
      closeComposer,
      resizePreview,
      setResizePreview,
    } = edit;

    // The root element (clipboard listeners fire only when it contains focus) and
    // the id to refocus after a keyboard-opened transient (editor / rename /
    // composer) closes (F-11).
    const rootRef = useRef<HTMLDivElement>(null);
    const restoreFocusRef = useRef<string | null>(null);

    // Drag-to-reschedule across the grid. A draggable event carries `{ occ }`; a
    // droppable day cell carries `{ dayMs }`. We shift by whole CALENDAR days
    // (date-fns `addDays`, DST-safe) and only carry the end when the item has a
    // real span (point events / milestones keep no end).
    const sensors = useSensors(
      useSensor(PointerSensor, { activationConstraint: { distance: 5 } }),
    );
    const onDragEnd = useCallback(
      (e: DragEndEvent) => {
        const occ = e.active.data.current?.occ as CalendarOccurrence | undefined;
        const targetDayMs = e.over?.data.current?.dayMs as number | undefined;
        if (!occ || targetDayMs == null) return;
        const sourceDayMs = startOfDay(occ.startMs).getTime();
        const deltaDays = differenceInCalendarDays(
          new Date(targetDayMs),
          new Date(sourceDayMs),
        );
        if (deltaDays === 0) return;
        const newStart = addDays(new Date(occ.startMs), deltaDays).getTime();
        const hasSpan = occ.endMs > occ.startMs;
        const newEnd = hasSpan
          ? addDays(new Date(occ.endMs), deltaDays).getTime()
          : undefined;
        rescheduleItem(
          occ.id,
          { startMs: newStart, endMs: newEnd, allDay: occ.allDay },
          "move",
        );
      },
      [rescheduleItem],
    );

    // onRangeChange — fire on mount + when the visible window changes. The
    // callback is read through a ref updated in an effect (never during render)
    // so an inline consumer callback doesn't retrigger the notify effect.
    const rangeStartMs = visibleRange.start.getTime();
    const rangeEndMs = visibleRange.end.getTime();
    const rangeCbRef = useRef(onRangeChange);
    useEffect(() => {
      rangeCbRef.current = onRangeChange;
    }, [onRangeChange]);
    useEffect(() => {
      rangeCbRef.current?.({
        view,
        start: new Date(rangeStartMs),
        end: new Date(rangeEndMs),
      });
    }, [view, rangeStartMs, rangeEndMs]);

    // Focus restore (F-11): when a keyboard-opened transient (editor / rename /
    // composer) closes, return focus to the originating event/cell.
    useEffect(() => {
      if (editingId || renamingId || composerTarget) return;
      const target = restoreFocusRef.current;
      if (!target) return;
      restoreFocusRef.current = null;
      const raf = requestAnimationFrame(() => {
        const sel = target.startsWith("day:")
          ? `[data-day-ms="${target.slice(4)}"]`
          : `[data-occ-id="${target}"]`;
        (rootRef.current?.querySelector(sel) as HTMLElement | null)?.focus();
      });
      return () => cancelAnimationFrame(raf);
    }, [editingId, renamingId, composerTarget]);

    // Cross-surface clipboard — copy/cut/paste `TodoItem`s through the OS clipboard
    // (the shared `ilinxa/task` envelope; foreign text is ignored). Document-level
    // so it fires regardless of which focused element the UA targets; gated on the
    // calendar containing focus, skipped over text inputs (so the composer / rename
    // keep native text copy/paste).
    useEffect(() => {
      if (!editable) return;
      const owns = () => {
        const active = document.activeElement;
        return !!rootRef.current && !!active && rootRef.current.contains(active);
      };
      const overText = () => {
        const el = document.activeElement as HTMLElement | null;
        return (
          el?.tagName === "INPUT" ||
          el?.tagName === "TEXTAREA" ||
          el?.isContentEditable === true
        );
      };
      // An open editor / rename / composer owns the clipboard (it may hold
      // non-input controls), so defer to native copy/paste while one is up.
      const busy = () =>
        editingId != null || renamingId != null || composerTarget != null;
      const targetId = (): string | null => {
        const active = document.activeElement as HTMLElement | null;
        const occId = active
          ?.closest?.("[data-occ-id]")
          ?.getAttribute("data-occ-id");
        return occId ?? selectedId ?? null;
      };
      const onCopy = (e: ClipboardEvent) => {
        if (!owns() || overText() || busy()) return;
        const id = targetId();
        const item = id ? getItem(id) : undefined;
        if (!item) return;
        writeTasksToClipboardEvent(e, [item], "calendar-01");
        e.preventDefault();
      };
      const onCut = (e: ClipboardEvent) => {
        if (!owns() || overText() || busy()) return;
        const id = targetId();
        const item = id ? getItem(id) : undefined;
        if (!item) return;
        writeTasksToClipboardEvent(e, [item], "calendar-01");
        deleteItem(item.id);
        e.preventDefault();
      };
      const onPaste = (e: ClipboardEvent) => {
        if (!owns() || overText() || busy()) return;
        const items = readTasksFromClipboardEvent(e);
        if (!items) return;
        pasteTasks(
          items,
          resolvePasteWindow(items, {
            activeEl: document.activeElement,
            occurrences,
            view,
            focusDate,
            scrollToHour,
          }),
        );
        e.preventDefault();
      };
      document.addEventListener("copy", onCopy);
      document.addEventListener("cut", onCut);
      document.addEventListener("paste", onPaste);
      return () => {
        document.removeEventListener("copy", onCopy);
        document.removeEventListener("cut", onCut);
        document.removeEventListener("paste", onPaste);
      };
    }, [
      editable,
      selectedId,
      getItem,
      deleteItem,
      pasteTasks,
      occurrences,
      view,
      focusDate,
      scrollToHour,
      editingId,
      renamingId,
      composerTarget,
    ]);

    useImperativeHandle(
      ref,
      (): CalendarHandle => ({
        goToDate,
        goToToday,
        setView,
        next,
        prev,
        getVisibleRange: () => ({
          start: new Date(rangeStartMs),
          end: new Date(rangeEndMs),
        }),
        // Editing (v0.2.0) — live; still no-op when !editable / permission denied.
        addTask: (date, item) =>
          createItem(null, item, {
            startMs: startOfDay(date).getTime(),
            allDay: true,
          }),
        deleteTask: (id) => deleteItem(id),
        editTask: (id) => openEditor(id),
        beginRename: (id) => beginRename(id),
        openQuickComposer: (date, allDay = true) =>
          openComposer({
            date: startOfDay(date),
            allDay,
            defaultEnd: allDay
              ? startOfDay(date)
              : new Date(date.getTime() + 3_600_000),
          }),
      }),
      [
        goToDate,
        goToToday,
        setView,
        next,
        prev,
        rangeStartMs,
        rangeEndMs,
        createItem,
        deleteItem,
        openEditor,
        beginRename,
        openComposer,
      ],
    );

    const ctx = useMemo<CalendarContextValue>(
      () => ({
        view,
        focusDate,
        visibleRange,
        weekStartsOn,
        availableViews,
        occurrences,
        nowMs,
        agendaRangeDays,
        maxEventsPerCell,
        scrollToHour,
        statusOptions,
        priorityOptions,
        labelOptions,
        selectedId,
        setView,
        goToDate,
        goToToday,
        next,
        prev,
        select,
        onTaskClick,
        onDateClick,
        onShowMore,
        renderTooltip,
        // editing (v0.2.0)
        editable,
        snap,
        quickCompose,
        permissions,
        getItem,
        can,
        rescheduleItem,
        createItem,
        deleteItem,
        renameItemAction,
        changeStatus,
        changePriority,
        applyEditedSubtree,
        editingId,
        openEditor,
        closeEditor,
        renamingId,
        beginRename,
        endRename,
        composerTarget,
        openComposer,
        closeComposer,
        resizePreview,
        setResizePreview,
        onExternalDrop,
        renderQuickComposer,
      }),
      [
        view,
        focusDate,
        visibleRange,
        weekStartsOn,
        availableViews,
        occurrences,
        nowMs,
        agendaRangeDays,
        maxEventsPerCell,
        scrollToHour,
        statusOptions,
        priorityOptions,
        labelOptions,
        selectedId,
        setView,
        goToDate,
        goToToday,
        next,
        prev,
        select,
        onTaskClick,
        onDateClick,
        onShowMore,
        renderTooltip,
        editable,
        snap,
        quickCompose,
        permissions,
        getItem,
        can,
        rescheduleItem,
        createItem,
        deleteItem,
        renameItemAction,
        changeStatus,
        changePriority,
        applyEditedSubtree,
        editingId,
        openEditor,
        closeEditor,
        renamingId,
        beginRename,
        endRename,
        composerTarget,
        openComposer,
        closeComposer,
        resizePreview,
        setResizePreview,
        onExternalDrop,
        renderQuickComposer,
      ],
    );

    // Event-focused editing. `←/→` move by one unit (day in month/agenda, snap in
    // the time grid), `Shift+←/→` (+ `↑/↓` in the time grid) resize the end,
    // `Delete` removes, `Enter` opens the detail editor, `F2` renames. Returns
    // true when it consumed the key (so chrome keys still fall through otherwise).
    const handleEventKey = (
      e: KeyboardEvent<HTMLDivElement>,
      id: string,
    ): boolean => {
      const occ = occurrences.find((o) => o.id === id);
      if (!occ) return false;
      const timed = (view === "week" || view === "day") && !occ.allDay;
      const moveUnit = timed ? snapStepMs(snap) || 900_000 : MS_PER_DAY;
      const hasSpan = occ.endMs > occ.startMs;

      // Resize the END by one unit. All-day events resize in whole days against
      // the exclusive-end convention (same math as the drag grip, so keyboard and
      // pointer agree — no off-by-one) and never collapse past their start;
      // milestones are points in time and aren't resizable.
      const resizeEnd = (dir: number) => {
        if (occ.kind === "milestone") return;
        if (occ.allDay) {
          const cov = coveredDays(occ);
          const curEnd = startOfDay(new Date(cov.lastMs)).getTime() + MS_PER_DAY;
          const minEnd = startOfDay(new Date(cov.firstMs)).getTime() + MS_PER_DAY;
          rescheduleItem(
            id,
            { endMs: Math.max(minEnd, curEnd + dir * MS_PER_DAY), allDay: true },
            "resize",
          );
        } else {
          const base = hasSpan ? occ.endMs : occ.startMs;
          rescheduleItem(
            id,
            { endMs: base + dir * (snapStepMs(snap) || 900_000), allDay: false },
            "resize",
          );
        }
      };

      switch (e.key) {
        case "ArrowLeft":
        case "ArrowRight": {
          const dir = e.key === "ArrowRight" ? 1 : -1;
          if (e.shiftKey) {
            resizeEnd(dir);
          } else {
            rescheduleItem(
              id,
              {
                startMs: occ.startMs + dir * moveUnit,
                endMs: hasSpan ? occ.endMs + dir * moveUnit : undefined,
                allDay: occ.allDay,
              },
              "move",
            );
          }
          e.preventDefault();
          return true;
        }
        case "ArrowUp":
        case "ArrowDown": {
          if (!timed || !e.shiftKey) return false; // resize-only, time grid only
          resizeEnd(e.key === "ArrowDown" ? 1 : -1);
          e.preventDefault();
          return true;
        }
        case "Delete":
        case "Backspace":
          deleteItem(id);
          e.preventDefault();
          return true;
        case "Enter":
          restoreFocusRef.current = id;
          openEditor(id);
          e.preventDefault();
          return true;
        case "F2":
          restoreFocusRef.current = id;
          beginRename(id);
          e.preventDefault();
          return true;
        default:
          return false;
      }
    };

    const handleKeyDown = (e: KeyboardEvent<HTMLDivElement>) => {
      const targetEl = e.target as HTMLElement;
      const tag = targetEl.tagName;
      if (tag === "INPUT" || tag === "TEXTAREA" || tag === "SELECT") return;
      // Route to event/cell editing when an event or editable day cell is focused;
      // anything not consumed falls through to the v1 view/period keys below.
      if (editable) {
        const occId = targetEl
          .closest?.("[data-occ-id]")
          ?.getAttribute("data-occ-id");
        if (occId) {
          if (handleEventKey(e, occId)) return;
        } else if (e.key === "Enter") {
          const dayMsAttr = targetEl
            .closest?.("[data-day-ms]")
            ?.getAttribute("data-day-ms");
          if (dayMsAttr) {
            const d = startOfDay(new Date(Number(dayMsAttr)));
            restoreFocusRef.current = `day:${dayMsAttr}`;
            openComposer({ date: d, allDay: true, defaultEnd: d });
            e.preventDefault();
            return;
          }
        }
      }
      switch (e.key) {
        case "ArrowLeft":
        case "PageUp":
          e.preventDefault();
          prev();
          break;
        case "ArrowRight":
        case "PageDown":
          e.preventDefault();
          next();
          break;
        case "t":
        case "T":
          e.preventDefault();
          goToToday();
          break;
        case "m":
        case "M":
          if (availableViews.includes("month")) setView("month");
          break;
        case "w":
        case "W":
          if (availableViews.includes("week")) setView("week");
          break;
        case "d":
        case "D":
          if (availableViews.includes("day")) setView("day");
          break;
        case "a":
        case "A":
          if (availableViews.includes("agenda")) setView("agenda");
          break;
      }
    };

    // DnD only mounts when editable — the read-only path stays DnD-free.
    const body = editable ? (
      <DndContext sensors={sensors} onDragEnd={onDragEnd}>
        {children}
      </DndContext>
    ) : (
      children
    );

    return (
      <CalendarContext.Provider value={ctx}>
        {/* No `delayDuration`: it's a Radix-only prop (Base UI's TooltipProvider
            takes `delay`), so passing it fails consumer-tsc on Base UI
            (F-cross-13). The default delay is cross-backend-safe. (v0.2.1) */}
        <TooltipProvider>
          <div
            ref={rootRef}
            tabIndex={0}
            onKeyDown={handleKeyDown}
            aria-label={props["aria-label"] ?? "Calendar"}
            className={cn(
              "flex flex-col overflow-hidden rounded-lg border border-border bg-card text-card-foreground outline-none focus-visible:ring-2 focus-visible:ring-ring",
              className,
            )}
          >
            {body}
          </div>
        </TooltipProvider>
      </CalendarContext.Provider>
    );
  },
);

"use client";

import { ChevronLeft, ChevronRight } from "lucide-react";
import { format } from "date-fns";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import { useCalendar } from "../hooks/use-calendar-context";
import type { CalendarView } from "../types";

const VIEW_LABELS: Record<CalendarView, string> = {
  month: "Month",
  week: "Week",
  day: "Day",
  agenda: "Agenda",
};

function periodLabel(
  view: CalendarView,
  focusDate: Date,
  range: { start: Date; end: Date },
): string {
  if (view === "month") return format(focusDate, "MMMM yyyy");
  if (view === "day") return format(focusDate, "EEEE, MMMM d, yyyy");
  // week + agenda → a range
  const sameYear = range.start.getFullYear() === range.end.getFullYear();
  return `${format(range.start, "MMM d")} – ${format(
    range.end,
    sameYear ? "MMM d, yyyy" : "MMM d, yyyy",
  )}`;
}

/** Toolbar (Tier B): period nav + label + view switch. */
export function CalendarToolbar({ className }: { className?: string }) {
  const {
    view,
    focusDate,
    visibleRange,
    availableViews,
    setView,
    next,
    prev,
    goToToday,
  } = useCalendar();

  return (
    <div
      className={cn(
        "flex flex-wrap items-center justify-between gap-2 border-b border-border p-2",
        className,
      )}
    >
      <div className="flex items-center gap-1">
        <Button variant="outline" size="sm" onClick={goToToday}>
          Today
        </Button>
        <Button
          variant="ghost"
          size="icon"
          aria-label="Previous period"
          onClick={prev}
        >
          <ChevronLeft className="size-4" />
        </Button>
        <Button
          variant="ghost"
          size="icon"
          aria-label="Next period"
          onClick={next}
        >
          <ChevronRight className="size-4" />
        </Button>
        <span className="ml-1 text-sm font-semibold text-foreground">
          {periodLabel(view, focusDate, visibleRange)}
        </span>
      </div>

      {availableViews.length > 1 ? (
        // Plain-button segmented control (NOT shadcn ToggleGroup): Base UI's
        // ToggleGroup is a multi-value model (`value: string[]`, `onValueChange:
        // (string[], details) => void`) while Radix's `type="single"` is a string
        // — so the single-select view switcher fails consumer-tsc on Base UI
        // (F-cross-13). Mirrors gantt-timeline-01's zoom switcher; drops the
        // `toggle-group` dep entirely. (v0.2.1)
        <div
          role="group"
          aria-label="Calendar view"
          className="inline-flex overflow-hidden rounded-md border border-border"
        >
          {availableViews.map((v) => (
            <button
              key={v}
              type="button"
              aria-pressed={view === v}
              aria-label={VIEW_LABELS[v]}
              onClick={() => setView(v)}
              className={cn(
                "h-8 px-3 text-sm font-medium transition-colors",
                view === v
                  ? "bg-primary text-primary-foreground"
                  : "bg-card text-muted-foreground hover:bg-muted hover:text-foreground",
              )}
            >
              {VIEW_LABELS[v]}
            </button>
          ))}
        </div>
      ) : null}
    </div>
  );
}

"use client";

import type { CSSProperties, MouseEvent as ReactMouseEvent } from "react";
import { useEffect, useRef, useState } from "react";
import { format, isSameDay, isSameMonth, startOfDay } from "date-fns";
import { useDroppable } from "@dnd-kit/core";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";
import { cn } from "@/lib/utils";
import { useCalendar } from "../hooks/use-calendar-context";
import { layoutMonthWeek, occurrencesOnDay } from "../lib/segments";
import { monthGrid } from "../lib/date-range";
import {
  CalendarEventBar,
  CalendarEventChip,
  EventHoverWrap,
} from "./calendar-event";
import { DraggableEventWrap } from "./calendar-edit-affordances";
import type { CalendarOccurrence, TodoItem } from "../types";

const DEFAULT_CAP = 3;
const LANE_H = "1.3rem";

/** One month-grid day cell (Tier C). Renders the cell chrome + day number +
 *  the "+N more" affordance; spanning events are overlaid by the view. The
 *  editable view passes `dropRef`/`isOver` (a @dnd-kit droppable) + a create
 *  click; read-only consumers omit them and the cell stays context-free. */
export function MonthDayCell({
  day,
  outside,
  today,
  hidden,
  hiddenItems,
  onDayClick,
  onDayDoubleClick,
  onShowMore,
  dropRef,
  isOver,
  creatable,
}: {
  day: Date;
  outside: boolean;
  today: boolean;
  hidden: number;
  hiddenItems: CalendarOccurrence[];
  onDayClick?: (d: Date) => void;
  onDayDoubleClick?: (d: Date, e: ReactMouseEvent) => void;
  onShowMore?: (d: Date, items: TodoItem[]) => void;
  dropRef?: (el: HTMLElement | null) => void;
  isOver?: boolean;
  creatable?: boolean;
}) {
  return (
    <div
      ref={dropRef}
      role="gridcell"
      // Editable cells are keyboard-focusable; the root's delegated handler reads
      // `data-day-ms` so Enter on a focused empty day opens the quick-composer.
      tabIndex={creatable ? 0 : undefined}
      data-day-ms={creatable ? startOfDay(day).getTime() : undefined}
      onClick={onDayClick ? () => onDayClick(day) : undefined}
      onDoubleClick={onDayDoubleClick ? (e) => onDayDoubleClick(day, e) : undefined}
      className={cn(
        "relative min-h-27 border-r border-border outline-none last:border-r-0",
        (onDayClick || creatable) && "cursor-pointer",
        creatable &&
          "focus-visible:outline-2 focus-visible:-outline-offset-2 focus-visible:outline-ring",
        outside && "bg-muted/30",
        isOver && "bg-primary/10 ring-1 ring-inset ring-primary/40",
      )}
    >
      <div className="flex items-center justify-end p-1">
        <span
          className={cn(
            "flex size-6 items-center justify-center rounded-full text-xs tabular-nums",
            outside ? "text-muted-foreground" : "text-foreground",
            today && "bg-primary font-semibold text-primary-foreground",
          )}
        >
          {format(day, "d")}
        </span>
      </div>
      {hidden > 0 ? (
        <div className="absolute inset-x-1 bottom-1">
          {onShowMore ? (
            <button
              type="button"
              onClick={(e) => {
                e.stopPropagation();
                onShowMore(day, hiddenItems.map((o) => o.item));
              }}
              className="w-full rounded-sm px-1 text-left text-xs text-muted-foreground hover:bg-muted hover:text-foreground"
            >
              +{hidden} more
            </button>
          ) : (
            <Popover>
              <PopoverTrigger asChild>
                <button
                  type="button"
                  onClick={(e) => e.stopPropagation()}
                  className="w-full rounded-sm px-1 text-left text-xs text-muted-foreground hover:bg-muted hover:text-foreground"
                >
                  +{hidden} more
                </button>
              </PopoverTrigger>
              <PopoverContent align="start" className="w-56 p-2">
                <p className="mb-1.5 px-1 text-xs font-medium text-muted-foreground">
                  {format(day, "EEEE, MMM d")}
                </p>
                <DayList day={day} items={hiddenItems} />
              </PopoverContent>
            </Popover>
          )}
        </div>
      ) : null}
    </div>
  );
}

function DayList({
  items,
}: {
  day: Date;
  items: CalendarOccurrence[];
}) {
  const { select, onTaskClick } = useCalendar();
  return (
    <div className="flex flex-col gap-1">
      {items.map((occ) => (
        <CalendarEventChip
          key={occ.id}
          occ={occ}
          onClick={() => {
            select(occ.id);
            onTaskClick?.(occ.item);
          }}
        />
      ))}
    </div>
  );
}

/** Editable droppable wrapper around a day cell (Tier B — editable only). */
function DroppableDayCell(props: {
  day: Date;
  outside: boolean;
  today: boolean;
  hidden: number;
  hiddenItems: CalendarOccurrence[];
  onShowMore?: (d: Date, items: TodoItem[]) => void;
}) {
  const { createItem, quickCompose, openComposer } = useCalendar();
  const dayMs = startOfDay(props.day).getTime();
  const { setNodeRef, isOver } = useDroppable({
    id: `day:${dayMs}`,
    data: { dayMs },
  });
  return (
    <MonthDayCell
      {...props}
      dropRef={setNodeRef}
      isOver={isOver}
      creatable
      onDayDoubleClick={(d, e) => {
        const startMs = startOfDay(d).getTime();
        if (quickCompose) {
          openComposer({
            date: new Date(startMs),
            allDay: true,
            defaultEnd: new Date(startMs),
            x: e.clientX,
            y: e.clientY,
          });
        } else {
          createItem(null, undefined, { startMs, allDay: true });
        }
      }}
    />
  );
}

/** Month view (Tier B). 7-column weekday grid; multi-day spanning bars + chips
 *  in lanes, "+N more" overflow per day. Editable: drag-to-reschedule (whole
 *  days), all-day bar resize, click-to-create, hover-delete. */
export function CalendarMonthView({ className }: { className?: string }) {
  const ctx = useCalendar();
  const {
    focusDate,
    weekStartsOn,
    occurrences,
    nowMs,
    maxEventsPerCell,
    selectedId,
    select,
    onTaskClick,
    onDateClick,
    onShowMore,
    renderTooltip,
    editable,
    can,
    resizePreview,
  } = ctx;

  const weeks = monthGrid(focusDate, weekStartsOn);
  const weeksCount = weeks.length;
  const nowDate = new Date(nowMs);

  // F-04 — height-responsive overflow cap: derive how many event lanes fit in a
  // measured week-row, so a taller calendar shows more events before "+N more".
  // `maxEventsPerCell` overrides (no measuring). rAF-coalesced ResizeObserver
  // (gantt G8); state is set only inside the rAF (never directly in the effect).
  const rowsRef = useRef<HTMLDivElement>(null);
  const [responsiveCap, setResponsiveCap] = useState(DEFAULT_CAP);
  useEffect(() => {
    const el = rowsRef.current;
    if (!el || maxEventsPerCell != null) return;
    let raf = 0;
    const ro = new ResizeObserver(() => {
      if (raf) return;
      raf = requestAnimationFrame(() => {
        raf = 0;
        const rowH = el.clientHeight / Math.max(1, weeksCount);
        const root =
          parseFloat(getComputedStyle(document.documentElement).fontSize) || 16;
        const laneH = root * 1.3 + 2; // LANE_H (1.3rem) + the grid's gap-y-0.5
        const next = Math.max(1, Math.floor((rowH - 34) / laneH)); // 34 ≈ day-number row
        setResponsiveCap((prev) => (prev === next ? prev : next));
      });
    });
    ro.observe(el);
    return () => {
      if (raf) cancelAnimationFrame(raf);
      ro.disconnect();
    };
  }, [maxEventsPerCell, weeksCount]);

  const cap = maxEventsPerCell ?? responsiveCap;
  // Apply the live resize preview to the occurrence being dragged.
  const occs = resizePreview
    ? occurrences.map((o) =>
        o.id === resizePreview.id
          ? { ...o, startMs: resizePreview.startMs, endMs: resizePreview.endMs }
          : o,
      )
    : occurrences;

  const activate = (occ: CalendarOccurrence) => {
    select(occ.id);
    onTaskClick?.(occ.item);
  };

  return (
    <div role="grid" className={cn("flex h-full flex-col", className)}>
      {/* weekday header */}
      <div role="row" className="grid grid-cols-7 border-b border-border">
        {weeks[0].map((d) => (
          <div
            key={d.toISOString()}
            role="columnheader"
            className="border-r border-border px-2 py-1.5 text-xs font-medium text-muted-foreground last:border-r-0"
          >
            {format(d, "EEE")}
          </div>
        ))}
      </div>

      {/* week rows — share the available height so the overflow cap is responsive */}
      <div ref={rowsRef} className="flex min-h-0 flex-1 flex-col">
        {weeks.map((week) => (
          <MonthWeekRow
            key={week[0].toISOString()}
            week={week}
            cap={cap}
            occurrences={occs}
            focusDate={focusDate}
            nowDate={nowDate}
            selectedId={selectedId}
            editable={editable}
            can={can}
            onDateClick={onDateClick}
            onShowMore={onShowMore}
            renderTooltip={renderTooltip}
            activate={activate}
          />
        ))}
      </div>
    </div>
  );
}

/** One week row — split out so it can own a stable ref for resize geometry. */
function MonthWeekRow({
  week,
  cap,
  occurrences,
  focusDate,
  nowDate,
  selectedId,
  editable,
  can,
  onDateClick,
  onShowMore,
  renderTooltip,
  activate,
}: {
  week: Date[];
  cap: number;
  occurrences: CalendarOccurrence[];
  focusDate: Date;
  nowDate: Date;
  selectedId: string | null;
  editable: boolean;
  can: ReturnType<typeof useCalendar>["can"];
  onDateClick?: (d: Date) => void;
  onShowMore?: (d: Date, items: TodoItem[]) => void;
  renderTooltip?: ReturnType<typeof useCalendar>["renderTooltip"];
  activate: (occ: CalendarOccurrence) => void;
}) {
  const weekRef = useRef<HTMLDivElement | null>(null);
  const layout = layoutMonthWeek(week, occurrences, cap);

  return (
    <div
      ref={weekRef}
      role="row"
      className="relative grid min-h-0 flex-1 grid-cols-7 border-b border-border last:border-b-0"
    >
      {week.map((day, col) => {
        const onDay = occurrencesOnDay(occurrences, day);
        const hiddenItems = onDay.filter(
          (o) => !layout.segments.some((s) => s.occ.id === o.id),
        );
        const cellProps = {
          day,
          outside: !isSameMonth(day, focusDate),
          today: isSameDay(day, nowDate),
          hidden: layout.overflow[col],
          hiddenItems,
          onShowMore,
        };
        return editable ? (
          <DroppableDayCell key={day.toISOString()} {...cellProps} />
        ) : (
          <MonthDayCell
            key={day.toISOString()}
            {...cellProps}
            onDayClick={onDateClick}
          />
        );
      })}

      {/* events overlay (bars + chips), placed by lane */}
      <div
        className="pointer-events-none absolute inset-x-0 top-8 grid grid-cols-7 gap-x-px gap-y-0.5 px-px"
        style={
          {
            gridTemplateRows: `repeat(${cap}, minmax(0, ${LANE_H}))`,
          } as CSSProperties
        }
      >
        {layout.segments.map((seg) => {
          const tooltip = renderTooltip
            ? renderTooltip(seg.occ.item, seg.occ)
            : undefined;
          const isBar = seg.spanning || seg.occ.allDay;
          const Event = isBar ? (
            <CalendarEventBar
              occ={seg.occ}
              selected={selectedId === seg.occ.id}
              continuesLeft={seg.continuesLeft}
              continuesRight={seg.continuesRight}
              onClick={() => activate(seg.occ)}
            />
          ) : (
            <CalendarEventChip
              occ={seg.occ}
              selected={selectedId === seg.occ.id}
              onClick={() => activate(seg.occ)}
            />
          );
          const canDrag = editable && can("move", seg.occ.item);
          // All-day bars (incl. single-day) get day-resize grips → drag an edge
          // to extend across days. Clipped (continues-left/right) bars can't.
          const resizable =
            editable &&
            seg.occ.allDay &&
            !seg.continuesLeft &&
            !seg.continuesRight &&
            can("resize", seg.occ.item);
          return (
            <div
              key={seg.occ.id}
              className="pointer-events-auto min-w-0"
              style={{
                gridColumn: `${seg.startCol + 1} / ${seg.endCol + 2}`,
                gridRow: seg.lane + 1,
              }}
            >
              {editable ? (
                <DraggableEventWrap
                  occ={seg.occ}
                  canDrag={canDrag}
                  resizable={resizable}
                  containerRef={weekRef}
                  cols={week}
                >
                  {Event}
                </DraggableEventWrap>
              ) : (
                <EventHoverWrap tooltip={tooltip}>{Event}</EventHoverWrap>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
}

"use client";

import type {
  MouseEvent as ReactMouseEvent,
  PointerEvent as ReactPointerEvent,
  RefObject,
} from "react";
import { useEffect, useRef } from "react";
import { format, isSameDay, startOfDay } from "date-fns";
import { useDroppable } from "@dnd-kit/core";
import { cn } from "@/lib/utils";
import { useCalendar } from "../hooks/use-calendar-context";
import { HOURS } from "../lib/date-range";
import { layoutMonthWeek } from "../lib/segments";
import { snapStepMs, snapToStep } from "../lib/edit-mutations";
import { packLanes } from "../lib/lane-pack";
import {
  CalendarEventBar,
  CalendarTimeBlock,
  EventHoverWrap,
  NowIndicator,
} from "./calendar-event";
import { DraggableEventWrap } from "./calendar-edit-affordances";
import { CalendarEventContextMenu } from "./calendar-context-menu";
import type {
  CalendarContextValue,
  CalendarOccurrence,
  CalendarSnap,
} from "../types";

const HOUR_PX = 48;
const DAY_PX = HOUR_PX * 24;
const MS_PER_DAY = 86_400_000;
const BAND_CAP = 99; // the all-day band grows to fit its lanes
const LANE_H = "1.4rem";

/** Left hour-label rail (Tier C). */
export function TimeGutter() {
  return (
    <div className="w-14 shrink-0 select-none" aria-hidden>
      {HOURS.map((h) => (
        <div key={h} style={{ height: HOUR_PX }} className="relative">
          {h > 0 ? (
            <span className="absolute -top-2 right-1.5 text-[0.65rem] tabular-nums text-muted-foreground">
              {format(new Date(2000, 0, 1, h), "h a")}
            </span>
          ) : null}
        </div>
      ))}
    </div>
  );
}

/* ───────── native-pointer gestures (the continuous time grid) ───────── */

/** Drag a timed block: vertical = time (delta), horizontal = day (target column). */
function startTimedMove(
  e: ReactPointerEvent,
  occ: CalendarOccurrence,
  gridRef: RefObject<HTMLDivElement | null>,
  columns: Date[],
  snap: CalendarSnap,
  reschedule: CalendarContextValue["rescheduleItem"],
  suppressClick: { current: boolean },
) {
  if (e.button !== 0) return;
  e.stopPropagation(); // keep the column's draw handler out of it
  const grid = gridRef.current;
  if (!grid) return;
  const startX = e.clientX;
  const startY = e.clientY;
  const timeOfDay = occ.startMs - startOfDay(occ.startMs).getTime();
  const dur = occ.endMs - occ.startMs;
  const step = snapStepMs(snap);
  let moved = false;
  const onMove = (ev: PointerEvent) => {
    if (
      !moved &&
      (Math.abs(ev.clientX - startX) > 4 || Math.abs(ev.clientY - startY) > 4)
    )
      moved = true;
  };
  const onUp = (ev: PointerEvent) => {
    window.removeEventListener("pointermove", onMove);
    window.removeEventListener("pointerup", onUp);
    if (!moved) return; // a click selects; only a real drag reschedules
    suppressClick.current = true;
    const rect = grid.getBoundingClientRect();
    const n = columns.length;
    const col = Math.max(
      0,
      Math.min(n - 1, Math.floor((ev.clientX - rect.left) / (rect.width / n))),
    );
    const dyMs = ((ev.clientY - startY) / DAY_PX) * MS_PER_DAY;
    const targetDayStart = startOfDay(columns[col]).getTime();
    const newStart = snapToStep(targetDayStart + timeOfDay + dyMs, targetDayStart, step);
    reschedule(occ.id, { startMs: newStart, endMs: newStart + dur, allDay: false }, "move");
  };
  window.addEventListener("pointermove", onMove);
  window.addEventListener("pointerup", onUp);
}

/** Drag a block's top/bottom edge: set start/end time (snapped). Updates the
 *  live preview each move; commits on release. */
function startTimedResize(
  e: ReactPointerEvent,
  occ: CalendarOccurrence,
  edge: "start" | "end",
  colRef: RefObject<HTMLDivElement | null>,
  dayStartMs: number,
  snap: CalendarSnap,
  reschedule: CalendarContextValue["rescheduleItem"],
  setPreview: CalendarContextValue["setResizePreview"],
) {
  e.stopPropagation();
  e.preventDefault();
  const col = colRef.current;
  if (!col) return;
  const step = snapStepMs(snap);
  const MIN = 60_000;
  const tAt = (clientY: number) => {
    const rect = col.getBoundingClientRect();
    return snapToStep(
      dayStartMs + ((clientY - rect.top) / rect.height) * MS_PER_DAY,
      dayStartMs,
      step,
    );
  };
  const onMove = (ev: PointerEvent) => {
    const t = tAt(ev.clientY);
    if (edge === "start") {
      setPreview({ id: occ.id, startMs: Math.min(t, occ.endMs - MIN), endMs: occ.endMs });
    } else {
      setPreview({ id: occ.id, startMs: occ.startMs, endMs: Math.max(t, occ.startMs + MIN) });
    }
  };
  const onUp = (ev: PointerEvent) => {
    window.removeEventListener("pointermove", onMove);
    window.removeEventListener("pointerup", onUp);
    setPreview(null);
    const t = tAt(ev.clientY);
    if (edge === "start") reschedule(occ.id, { startMs: t, allDay: false }, "resize");
    else reschedule(occ.id, { endMs: t, allDay: false }, "resize");
  };
  window.addEventListener("pointermove", onMove);
  window.addEventListener("pointerup", onUp);
}

const COL_MS = (clientY: number, rect: DOMRect, dayStartMs: number, step: number) =>
  snapToStep(
    dayStartMs + ((clientY - rect.top) / rect.height) * MS_PER_DAY,
    dayStartMs,
    step,
  );

/** Request to create over a window — routes through the quick-composer or a
 *  direct create (the column owns the decision via `quickCompose`). */
type RequestCreate = (
  win: { startMs: number; endMs?: number; allDay: boolean },
  x: number,
  y: number,
) => void;

/** Drag across an empty column → create a timed event spanning the range. A
 *  single click does NOT create (that's a double-click); only a real drag does. */
function startDraw(
  e: ReactPointerEvent,
  colRef: RefObject<HTMLDivElement | null>,
  dayStartMs: number,
  snap: CalendarSnap,
  request: RequestCreate,
) {
  if (e.button !== 0) return;
  const col = colRef.current;
  if (!col) return;
  const step = snapStepMs(snap) || 900_000;
  const startMs = COL_MS(e.clientY, col.getBoundingClientRect(), dayStartMs, step);
  const startY = e.clientY;
  let moved = false;
  const onMove = (ev: PointerEvent) => {
    if (!moved && Math.abs(ev.clientY - startY) > 4) moved = true;
  };
  const onUp = (ev: PointerEvent) => {
    window.removeEventListener("pointermove", onMove);
    window.removeEventListener("pointerup", onUp);
    if (!moved) return; // a click selects/deselects; only a drag creates
    const endMs = COL_MS(ev.clientY, col.getBoundingClientRect(), dayStartMs, step);
    const lo = Math.min(startMs, endMs);
    let hi = Math.max(startMs, endMs);
    if (hi <= lo) hi = lo + (step || 900_000);
    request({ startMs: lo, endMs: hi, allDay: false }, ev.clientX, ev.clientY);
  };
  window.addEventListener("pointermove", onMove);
  window.addEventListener("pointerup", onUp);
}

/** Double-click an empty slot → create a default 1-hour timed event there. */
function createAtDoubleClick(
  e: ReactMouseEvent,
  colRef: RefObject<HTMLDivElement | null>,
  dayStartMs: number,
  snap: CalendarSnap,
  request: RequestCreate,
) {
  if ((e.target as HTMLElement).closest("button")) return; // not on an event
  const col = colRef.current;
  if (!col) return;
  const step = snapStepMs(snap) || 900_000;
  const startMs = COL_MS(e.clientY, col.getBoundingClientRect(), dayStartMs, step);
  request(
    { startMs, endMs: startMs + 3_600_000, allDay: false },
    e.clientX,
    e.clientY,
  );
}

/* ───────── all-day band (F-03: column-spanning bars) ───────── */

/** Editable droppable + click-create cell beneath the band overlay. */
function BandDropCell({ day }: { day: Date }) {
  const { createItem, quickCompose, openComposer } = useCalendar();
  const dayMs = startOfDay(day).getTime();
  const { setNodeRef, isOver } = useDroppable({
    id: `band:${dayMs}`,
    data: { dayMs },
  });
  return (
    <div
      ref={setNodeRef}
      // Double-click to create (parity with month/time-grid; honors quickCompose).
      onDoubleClick={(e) => {
        if (quickCompose) {
          openComposer({
            date: new Date(dayMs),
            allDay: true,
            defaultEnd: new Date(dayMs),
            x: e.clientX,
            y: e.clientY,
          });
        } else {
          createItem(null, undefined, { startMs: dayMs, allDay: true });
        }
      }}
      className={cn(
        "min-h-7 cursor-pointer border-l border-border first:border-l-0",
        isOver && "bg-primary/10",
      )}
    />
  );
}

/** The all-day band — spanning bars laid out like the month grid (F-03). */
function AllDayBand({ columns }: { columns: Date[] }) {
  const {
    occurrences,
    selectedId,
    select,
    onTaskClick,
    renderTooltip,
    editable,
    can,
    resizePreview,
  } = useCalendar();
  const overlayRef = useRef<HTMLDivElement>(null);
  const n = columns.length;

  // Apply the live resize preview, then take all-day occurrences in range.
  const occs = resizePreview
    ? occurrences.map((o) =>
        o.id === resizePreview.id
          ? { ...o, startMs: resizePreview.startMs, endMs: resizePreview.endMs }
          : o,
      )
    : occurrences;
  const firstMs = startOfDay(columns[0]).getTime();
  const lastMs = startOfDay(columns[n - 1]).getTime() + MS_PER_DAY;
  const allDay = occs.filter(
    (o) => !o.invalid && o.allDay && o.endMs > firstMs && o.startMs < lastMs,
  );
  const layout = layoutMonthWeek(columns, allDay, BAND_CAP);
  const laneCount = Math.max(1, layout.laneCount);

  const activate = (occ: CalendarOccurrence) => {
    select(occ.id);
    onTaskClick?.(occ.item);
  };

  return (
    <div className="flex border-b border-border">
      <div className="flex w-14 shrink-0 items-start justify-end pr-1.5 pt-1 text-[0.6rem] uppercase text-muted-foreground">
        all day
      </div>
      <div className="relative flex-1">
        {/* base cells (droppable + click-create when editable) */}
        <div className="grid" style={{ gridTemplateColumns: `repeat(${n}, 1fr)` }}>
          {columns.map((day) =>
            editable ? (
              <BandDropCell key={day.toISOString()} day={day} />
            ) : (
              <div
                key={day.toISOString()}
                className="min-h-7 border-l border-border first:border-l-0"
              />
            ),
          )}
        </div>
        {/* spanning-bar overlay */}
        <div
          ref={overlayRef}
          className="pointer-events-none absolute inset-0 grid gap-x-px gap-y-0.5 p-0.5"
          style={{
            gridTemplateColumns: `repeat(${n}, 1fr)`,
            gridTemplateRows: `repeat(${laneCount}, ${LANE_H})`,
          }}
        >
          {layout.segments.map((seg) => {
            const Bar = (
              <CalendarEventBar
                occ={seg.occ}
                selected={selectedId === seg.occ.id}
                continuesLeft={seg.continuesLeft}
                continuesRight={seg.continuesRight}
                onClick={() => activate(seg.occ)}
              />
            );
            const canDrag = editable && can("move", seg.occ.item);
            const resizable =
              editable &&
              !seg.continuesLeft &&
              !seg.continuesRight &&
              can("resize", seg.occ.item);
            return (
              <div
                key={seg.occ.id}
                className="pointer-events-auto min-w-0"
                style={{
                  gridColumn: `${seg.startCol + 1} / ${seg.endCol + 2}`,
                  gridRow: seg.lane + 1,
                }}
              >
                {editable ? (
                  <DraggableEventWrap
                    occ={seg.occ}
                    canDrag={canDrag}
                    resizable={resizable}
                    containerRef={overlayRef}
                    cols={columns}
                  >
                    {Bar}
                  </DraggableEventWrap>
                ) : (
                  <EventHoverWrap tooltip={renderTooltip?.(seg.occ.item, seg.occ)}>
                    {Bar}
                  </EventHoverWrap>
                )}
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}

/* ───────── timed day column ───────── */

function DayColumn({
  day,
  columns,
  gridRef,
}: {
  day: Date;
  columns: Date[];
  gridRef: RefObject<HTMLDivElement | null>;
}) {
  const {
    occurrences,
    nowMs,
    selectedId,
    select,
    onTaskClick,
    renderTooltip,
    editable,
    can,
    snap,
    rescheduleItem,
    createItem,
    quickCompose,
    openComposer,
    resizePreview,
    setResizePreview,
  } = useCalendar();
  const colRef = useRef<HTMLDivElement>(null);
  const suppressClick = useRef(false);

  const requestCreate: RequestCreate = (win, x, y) => {
    if (quickCompose) {
      openComposer({
        date: new Date(win.startMs),
        allDay: win.allDay,
        defaultEnd: new Date(win.endMs ?? win.startMs),
        x,
        y,
      });
    } else {
      createItem(null, undefined, win);
    }
  };

  const dayStartMs = startOfDay(day).getTime();
  const dayEndMs = dayStartMs + MS_PER_DAY;
  const timed = occurrences.filter(
    (o) => !o.invalid && !o.allDay && o.endMs > dayStartMs && o.startMs < dayEndMs,
  );
  const blocks = packLanes(timed);
  const showNow = isSameDay(day, new Date(nowMs));
  const nowFrac = (nowMs - dayStartMs) / MS_PER_DAY;

  const activate = (occ: CalendarOccurrence) => {
    if (suppressClick.current) {
      suppressClick.current = false;
      return;
    }
    select(occ.id);
    onTaskClick?.(occ.item);
  };

  return (
    <div
      ref={colRef}
      className="relative flex-1 border-l border-border"
      style={{ height: DAY_PX }}
      onPointerDown={
        editable
          ? (e) => startDraw(e, colRef, dayStartMs, snap, requestCreate)
          : undefined
      }
      onDoubleClick={
        editable
          ? (e) => createAtDoubleClick(e, colRef, dayStartMs, snap, requestCreate)
          : undefined
      }
    >
      {HOURS.map((h) => (
        <div
          key={h}
          style={{ height: HOUR_PX }}
          className="border-t border-border/50 first:border-t-0"
        />
      ))}
      {showNow && nowFrac >= 0 && nowFrac <= 1 ? (
        <NowIndicator topFraction={nowFrac} />
      ) : null}
      {blocks.map((b) => {
        // Apply the live resize preview to THIS block's geometry mid-gesture.
        const pv = resizePreview?.id === b.occ.id ? resizePreview : null;
        const sMs = pv ? pv.startMs : b.occ.startMs;
        const eMs = pv ? pv.endMs : b.occ.endMs;
        const top = Math.max(0, (sMs - dayStartMs) / MS_PER_DAY);
        const height = Math.min(1 - top, Math.max((eMs - sMs) / MS_PER_DAY, 0.02));
        const canMove = editable && can("move", b.occ.item);
        const canResize = editable && can("resize", b.occ.item);
        const Block = (
          <CalendarTimeBlock
            occ={b.occ}
            selected={selectedId === b.occ.id}
            onClick={() => activate(b.occ)}
            onPointerDown={
              editable
                ? (e) => {
                    e.stopPropagation(); // don't let a block click start a draw
                    if (canMove)
                      startTimedMove(
                        e,
                        b.occ,
                        gridRef,
                        columns,
                        snap,
                        rescheduleItem,
                        suppressClick,
                      );
                  }
                : undefined
            }
            top={top}
            height={height}
            left={b.lane / b.laneCount}
            width={1 / b.laneCount}
          />
        );
        return (
          <div key={b.occ.id} className="contents">
            {editable ? (
              <CalendarEventContextMenu item={b.occ.item}>
                {Block}
              </CalendarEventContextMenu>
            ) : (
              <EventHoverWrap tooltip={renderTooltip?.(b.occ.item, b.occ)}>
                {Block}
              </EventHoverWrap>
            )}
            {editable && canResize ? (
              <div
                className="pointer-events-none absolute z-20"
                style={{
                  top: `${top * 100}%`,
                  height: `${height * 100}%`,
                  left: `calc(${(b.lane / b.laneCount) * 100}% + 1px)`,
                  width: `calc(${(1 / b.laneCount) * 100}% - 2px)`,
                }}
              >
                <div
                  role="button"
                  aria-label="Resize start"
                  onPointerDown={(e) =>
                    startTimedResize(e, b.occ, "start", colRef, dayStartMs, snap, rescheduleItem, setResizePreview)
                  }
                  className="pointer-events-auto absolute inset-x-0 top-0 flex h-2 cursor-ns-resize items-center justify-center"
                >
                  <span className="h-0.5 w-5 rounded-full bg-current opacity-40" aria-hidden />
                </div>
                <div
                  role="button"
                  aria-label="Resize end"
                  onPointerDown={(e) =>
                    startTimedResize(e, b.occ, "end", colRef, dayStartMs, snap, rescheduleItem, setResizePreview)
                  }
                  className="pointer-events-auto absolute inset-x-0 bottom-0 flex h-2 cursor-ns-resize items-center justify-center"
                >
                  <span className="h-0.5 w-5 rounded-full bg-current opacity-40" aria-hidden />
                </div>
              </div>
            ) : null}
          </div>
        );
      })}
    </div>
  );
}

/**
 * The hour time-grid (Tier C), shared by Week (7 columns) and Day (1 column):
 * column headers + all-day band (spanning bars) + a scrollable 24h grid with
 * lane-packed timed blocks and a now-line on today. Editable: native-pointer
 * timed move/resize + draw-to-create; the all-day band drags by whole days.
 */
export function TimeGrid({
  columns,
  className,
}: {
  columns: Date[];
  className?: string;
}) {
  const { nowMs, scrollToHour } = useCalendar();
  const scrollRef = useRef<HTMLDivElement>(null);
  const gridRef = useRef<HTMLDivElement>(null);
  useEffect(() => {
    const el = scrollRef.current;
    if (!el) return;
    const hour = Math.max(0, Math.min(23, scrollToHour));
    el.scrollTop = (hour / 24) * el.scrollHeight;
  }, [scrollToHour]);

  const nowDate = new Date(nowMs);

  return (
    <div className={cn("flex flex-col", className)}>
      {/* column headers */}
      <div className="flex border-b border-border">
        <div className="w-14 shrink-0" />
        {columns.map((day) => (
          <div
            key={day.toISOString()}
            className="flex-1 border-l border-border px-2 py-1.5 text-center"
          >
            <div className="text-xs text-muted-foreground">{format(day, "EEE")}</div>
            <div
              className={cn(
                "text-sm font-semibold tabular-nums",
                isSameDay(day, nowDate) ? "text-primary" : "text-foreground",
              )}
            >
              {format(day, "d")}
            </div>
          </div>
        ))}
      </div>

      {/* all-day band */}
      <AllDayBand columns={columns} />

      {/* scrollable hour grid */}
      <div ref={scrollRef} className="flex max-h-128 overflow-y-auto">
        <TimeGutter />
        <div ref={gridRef} className="flex flex-1">
          {columns.map((day) => (
            <DayColumn
              key={day.toISOString()}
              day={day}
              columns={columns}
              gridRef={gridRef}
            />
          ))}
        </div>
      </div>
    </div>
  );
}

