        )}
      >
        <span className="flex items-center gap-1">
          <PriorityFlag color={occ.flagColor} />
          <span className="truncate font-medium">{occ.item.name}</span>
        </span>
        {!milestone && height > 0.04 ? (
          <span className="truncate tabular-nums opacity-75">
