/** A horizontal "now" line crossing a day column (Tier C). */
export function NowIndicator({
  topFraction,
  className,
}: {
  topFraction: number;
  className?: string;
}) {
  return (
    <div
      aria-hidden
      style={{ top: `${topFraction * 100}%` }}
      className={cn(
        "pointer-events-none absolute inset-x-0 z-30 flex items-center",
