import { lazy, Suspense } from "react";
import type { TodoColorRamp, TodoItem, TodoStatusOption } from "../types";

/**
 * Lazy-embeds the full `<TodoRichCard>` (Tier C). Pass this to `renderTooltip`
 * for a rich hover card. `React.lazy` keeps todo-rich-card OUT of the bundle
 * unless a consumer actually wires this in — the default lightweight tooltip
 * pulls nothing. Same-category relative dynamic import (rewriter-safe).
 */
const LazyTodoRichCard = lazy(() =>
  import("../../todo-rich-card").then((m) => ({ default: m.TodoRichCard })),
);

export function CalendarFullCardTooltip({
  item,
  statusOptions,
  colorRamp,
}: {
  item: TodoItem;
  statusOptions?: TodoStatusOption[];
  colorRamp?: TodoColorRamp;
}) {
  return (
    <div className="w-72">
      <Suspense
        fallback={
          <div className="p-3 text-xs text-muted-foreground">Loading…</div>
        }
      >
        <LazyTodoRichCard
          value={item}
          statusOptions={statusOptions}
          colorRamp={colorRamp}
        />
      </Suspense>
    </div>
  );
}

"use client";

/**
 * Shared editable affordances for the DAY-GRANULAR surfaces — the month grid and
 * the week/day all-day band. Both make events @dnd-kit draggables (drops resolve
 * in `Calendar01Root`'s `onDragEnd` by whole calendar days) and add edge-resize
 * grips (native pointer, clientX → column → day) + a hover-delete. The continuous
 * TIME grid uses its own native-pointer layer (see calendar-time-grid.tsx).
 */

import type {
  PointerEvent as ReactPointerEvent,
  ReactNode,
  RefObject,
} from "react";
import { addDays, startOfDay } from "date-fns";
import { useDraggable } from "@dnd-kit/core";
import { CSS } from "@dnd-kit/utilities";
import { cn } from "@/lib/utils";
import { useCalendar } from "../hooks/use-calendar-context";
import { coveredDays } from "../lib/segments";
import { CalendarEventContextMenu } from "./calendar-context-menu";
import type { CalendarOccurrence } from "../types";

/** Edge grip on an all-day bar → native-pointer DAY resize (clientX → column). */
export function DayResizeGrip({
  edge,
  occ,
  containerRef,
  cols,
}: {
  edge: "start" | "end";
  occ: CalendarOccurrence;
  containerRef: RefObject<HTMLDivElement | null>;
  cols: Date[];
}) {
  const { rescheduleItem, setResizePreview } = useCalendar();
  const colAt = (clientX: number): number => {
    const el = containerRef.current;
    if (!el) return 0;
    const r = el.getBoundingClientRect();
    return Math.max(
      0,
      Math.min(cols.length - 1, Math.floor((clientX - r.left) / (r.width / cols.length))),
    );
  };
  const onPointerDown = (e: ReactPointerEvent) => {
    e.stopPropagation(); // keep the @dnd-kit drag sensor + draw out of it
    e.preventDefault();
    const span = coveredDays(occ);
    // Resolve the edit window (start ms or exclusive-end ms) for a target column.
    const windowAt = (clientX: number) => {
      const dayMs = startOfDay(cols[colAt(clientX)]).getTime();
      if (edge === "start") {
        const startMs = Math.min(dayMs, startOfDay(span.lastMs).getTime());
        return { startMs, endMs: occ.endMs };
      }
      const lastDay = Math.max(dayMs, startOfDay(span.firstMs).getTime());
      return {
        startMs: occ.startMs,
        endMs: startOfDay(addDays(new Date(lastDay), 1)).getTime(),
      };
    };
    const onMove = (ev: PointerEvent) => {
      const w = windowAt(ev.clientX);
      setResizePreview({ id: occ.id, startMs: w.startMs, endMs: w.endMs });
    };
    const onUp = (ev: PointerEvent) => {
      window.removeEventListener("pointermove", onMove);
      window.removeEventListener("pointerup", onUp);
      setResizePreview(null);
      const w = windowAt(ev.clientX);
      rescheduleItem(
        occ.id,
        edge === "start"
          ? { startMs: w.startMs, allDay: true }
          : { endMs: w.endMs, allDay: true },
        "resize",
      );
    };
    window.addEventListener("pointermove", onMove);
    window.addEventListener("pointerup", onUp);
  };
  return (
    <button
      type="button"
      aria-label={edge === "start" ? "Resize start" : "Resize end"}
      onPointerDown={onPointerDown}
      onClick={(e) => e.stopPropagation()}
      className={cn(
        "absolute inset-y-0 z-10 hidden w-2.5 cursor-ew-resize items-center justify-center group-hover:flex",
        edge === "start" ? "left-0" : "right-0",
      )}
    >
      <span
        className="h-1/2 w-0.5 rounded-full bg-current opacity-60"
        aria-hidden
      />
    </button>
  );
}

/** Editable wrapper around an all-day segment: @dnd-kit draggable + edge resize
 *  (when `resizable`) + hover-delete. Used by the month grid and the all-day band. */
export function DraggableEventWrap({
  occ,
  canDrag,
  resizable,
  containerRef,
  cols,
  children,
}: {
  occ: CalendarOccurrence;
  canDrag: boolean;
  resizable: boolean;
  containerRef: RefObject<HTMLDivElement | null>;
  cols: Date[];
  children: ReactNode;
}) {
  const { attributes, listeners, setNodeRef, transform, isDragging } =
    useDraggable({ id: occ.id, data: { occ }, disabled: !canDrag });
  return (
    <div
      ref={setNodeRef}
      {...(canDrag ? listeners : {})}
      {...attributes}
      style={transform ? { transform: CSS.Translate.toString(transform) } : undefined}
      className={cn(
        "group relative",
        canDrag && "cursor-grab active:cursor-grabbing",
        isDragging && "z-30 opacity-60",
      )}
    >
      <CalendarEventContextMenu item={occ.item}>{children}</CalendarEventContextMenu>
      {resizable ? (
        <>
          <DayResizeGrip edge="start" occ={occ} containerRef={containerRef} cols={cols} />
          <DayResizeGrip edge="end" occ={occ} containerRef={containerRef} cols={cols} />
        </>
      ) : null}
    </div>
  );
}

"use client";

/**
 * Right-click action menu (Tier B). Wraps an event and offers permission-gated
 * Edit / Status / Priority / Delete. Every action routes through the same
 * `use-calendar-edit` dispatchers as the pointer paths (single chokepoint). When
 * editing is off or nothing is permitted, it renders the child unwrapped — zero
 * overhead in the read-only path. Mirrors gantt's `GanttContextMenu`
 * (`ContextMenuTrigger asChild` is the cross-backend-safe shape).
 */

import type { ReactNode } from "react";
import {
  ContextMenu,
  ContextMenuContent,
  ContextMenuItem,
  ContextMenuSeparator,
  ContextMenuSub,
  ContextMenuSubContent,
  ContextMenuSubTrigger,
  ContextMenuTrigger,
} from "@/components/ui/context-menu";
import { useCalendar } from "../hooks/use-calendar-context";
import { serializeTasks } from "../lib/clipboard";
import type { TodoItem } from "../types";

export function CalendarEventContextMenu({
  item,
  children,
}: {
  item: TodoItem;
  children: ReactNode;
}) {
  const ctx = useCalendar();
  const canEdit = ctx.editable && ctx.can("editDetails", item);
  const canDelete = ctx.editable && ctx.can("delete", item);
  const statusOptions = ctx.statusOptions ?? [];
  const priorityOptions = ctx.priorityOptions ?? [];

  // When editable, the menu always offers Copy (reading data needs no edit/delete
  // permission); other items are capability-gated. Read-only → child unwrapped.
  if (!ctx.editable) return <>{children}</>;

  const copy = () => {
    void navigator.clipboard?.writeText(serializeTasks([item], "calendar-01"));
  };
  const cut = () => {
    // Don't delete-without-copy: if the clipboard is unavailable (insecure
    // context) the menu cut is a no-op (the keyboard Cut, which uses the sync
    // clipboard event, still works).
    if (!navigator.clipboard) return;
    void navigator.clipboard.writeText(serializeTasks([item], "calendar-01"));
    ctx.deleteItem(item.id);
  };

  return (
    <ContextMenu>
      <ContextMenuTrigger asChild>{children}</ContextMenuTrigger>
      <ContextMenuContent className="w-44">
        {canEdit ? (
          <ContextMenuItem onSelect={() => ctx.openEditor(item.id)}>
            Edit…
          </ContextMenuItem>
        ) : null}

        {canEdit ? (
          <ContextMenuItem onSelect={() => ctx.beginRename(item.id)}>
            Rename
          </ContextMenuItem>
        ) : null}

        {canEdit && statusOptions.length > 0 ? (
          <ContextMenuSub>
            <ContextMenuSubTrigger>Status</ContextMenuSubTrigger>
            <ContextMenuSubContent>
              {statusOptions.map((o) => (
                <ContextMenuItem
                  key={o.value}
                  onSelect={() => ctx.changeStatus(item.id, o.value)}
                >
                  {o.label}
                </ContextMenuItem>
              ))}
            </ContextMenuSubContent>
          </ContextMenuSub>
        ) : null}

        {canEdit && priorityOptions.length > 0 ? (
          <ContextMenuSub>
            <ContextMenuSubTrigger>Priority</ContextMenuSubTrigger>
            <ContextMenuSubContent>
              {priorityOptions.map((o) => (
                <ContextMenuItem
                  key={o.value}
                  onSelect={() => ctx.changePriority(item.id, o.value)}
                >
                  {o.label}
                </ContextMenuItem>
              ))}
            </ContextMenuSubContent>
          </ContextMenuSub>
        ) : null}

        {canEdit ? <ContextMenuSeparator /> : null}
        <ContextMenuItem onSelect={copy}>Copy</ContextMenuItem>
        {canDelete ? (
          <ContextMenuItem onSelect={cut}>Cut</ContextMenuItem>
        ) : null}

        {canDelete ? (
          <>
            <ContextMenuSeparator />
            <ContextMenuItem
              variant="destructive"
              onSelect={() => ctx.deleteItem(item.id)}
            >
              Delete
            </ContextMenuItem>
          </>
        ) : null}
      </ContextMenuContent>
    </ContextMenu>
  );
}

"use client";

/**
 * Quick-create composer (Tier B + Tier C). When a create gesture sets
 * `composerTarget`, this floats a small title-entry popup at the pointer:
 * type a title + Enter to create, or "More options" to open the full editor.
 * Deliberately a plain fixed-position panel (NOT a Radix Popover) to dodge the
 * Base-UI `PopoverAnchor`/`asChild` divergence (the engagement-bar lesson).
 * Mounted by the assembly; reads context (lives inside `Calendar01Root`).
 */

import { useState } from "react";
import type { ReactNode } from "react";
import { format } from "date-fns";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { useCalendar } from "../hooks/use-calendar-context";
import type {
  CalendarComposerTarget,
  CalendarContextValue,
  TodoItem,
} from "../types";

function whenText(t: CalendarComposerTarget): string {
  if (t.allDay) return `${format(t.date, "EEE, MMM d")} · all day`;
  return `${format(t.date, "EEE, MMM d")} · ${format(t.date, "p")} – ${format(
    t.defaultEnd,
    "p",
  )}`;
}

function windowOf(t: CalendarComposerTarget) {
  const endMs =
    t.allDay && t.defaultEnd.getTime() === t.date.getTime()
      ? undefined
      : t.defaultEnd.getTime();
  return { startMs: t.date.getTime(), endMs, allDay: t.allDay };
}

function Floating({
  x,
  y,
  onClose,
  children,
}: {
  x: number;
  y: number;
  onClose: () => void;
  children: ReactNode;
}) {
  return (
    <>
      <div className="fixed inset-0 z-40" onClick={onClose} aria-hidden />
      <div
        role="dialog"
        aria-label="Create event"
        className="fixed z-50 w-64 rounded-lg border border-border bg-popover p-3 text-popover-foreground shadow-lg"
        style={{ left: x, top: y }}
      >
        {children}
      </div>
    </>
  );
}

function ComposerPopup({
  target,
  onClose,
  onCreate,
  render,
}: {
  target: CalendarComposerTarget;
  onClose: () => void;
  onCreate: CalendarContextValue["createItem"];
  render?: CalendarContextValue["renderQuickComposer"];
}) {
  const [title, setTitle] = useState("");
  const commit = (seed?: Partial<TodoItem>) =>
    onCreate(
      null,
      { name: title.trim() || "New event", ...seed },
      windowOf(target),
    );
  const openFull = () =>
    onCreate(null, { name: title.trim() || "New event" }, windowOf(target), {
      openEditor: true,
    });

  const vw = typeof window !== "undefined" ? window.innerWidth : 1024;
  const vh = typeof window !== "undefined" ? window.innerHeight : 768;
  const x = Math.max(8, Math.min(target.x ?? 80, vw - 272));
  const y = Math.max(8, Math.min(target.y ?? 80, vh - 180));

  if (render) {
    return (
      <Floating x={x} y={y} onClose={onClose}>
        {render({
          date: target.date,
          allDay: target.allDay,
          defaultEnd: target.defaultEnd,
          commit,
          cancel: onClose,
          openFull,
        })}
      </Floating>
    );
  }

  return (
    <Floating x={x} y={y} onClose={onClose}>
      <form
        onSubmit={(e) => {
          e.preventDefault();
          commit();
        }}
        className="flex flex-col gap-2"
      >
        <p className="text-xs text-muted-foreground">{whenText(target)}</p>
        <Input
          autoFocus
          value={title}
          onChange={(e) => setTitle(e.target.value)}
          onKeyDown={(e) => {
            if (e.key === "Escape") onClose();
          }}
          placeholder="Add title"
          className="h-8"
        />
        <div className="flex items-center justify-between">
          <button
            type="button"
            onClick={openFull}
            className="text-xs text-muted-foreground underline-offset-2 hover:text-foreground hover:underline"
          >
            More options
          </button>
          <div className="flex gap-1.5">
            <Button type="button" size="sm" variant="ghost" onClick={onClose}>
              Cancel
            </Button>
            <Button type="submit" size="sm">
              Create
            </Button>
          </div>
        </div>
      </form>
    </Floating>
  );
}

export function CalendarQuickComposer() {
  const { composerTarget, closeComposer, createItem, renderQuickComposer } =
    useCalendar();
  if (!composerTarget) return null;
  return (
    <ComposerPopup
      key={`${composerTarget.date.getTime()}:${composerTarget.x ?? 0}:${composerTarget.y ?? 0}`}
      target={composerTarget}
      onClose={closeComposer}
      onCreate={createItem}
      render={renderQuickComposer}
    />
  );
}

"use client";

import { useMemo } from "react";
import { format } from "date-fns";
import { Pencil, Trash2, X } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { cn } from "@/lib/utils";
import { useCalendar } from "../hooks/use-calendar-context";
import { coveredDays } from "../lib/segments";
import { EventEditorPanel } from "./calendar-edit-overlays";
import type { CalendarOccurrence } from "../types";

/**
 * Selected-event inspector (Tier B). Shows a read-only preview of the selected
 * occurrence; when `editable`, an Edit button reveals the shared `EventEditorPanel`
 * (the full lazy `<TodoRichCard editable>` — title, status, priority, dates,
 * description) whose edits splice back via `applyEditedSubtree`, plus Delete.
 * Lives inside `Calendar01Root` (reads context). Place it beside the views for
 * a persistent details panel, or omit it (the editor also surfaces via the
 * `CalendarEventEditorOverlay` the assembly mounts when there's no inspector).
 */

function whenLabel(occ: CalendarOccurrence): string {
  const s = new Date(occ.startMs);
  if (occ.kind === "milestone") return format(s, "PPP 'at' p");
  if (occ.allDay) {
    const last = new Date(coveredDays(occ).lastMs);
    return format(s, "yyyy-MM-dd") === format(last, "yyyy-MM-dd")
      ? `${format(s, "PPP")} (all day)`
      : `${format(s, "PPP")} – ${format(last, "PPP")}`;
  }
  return `${format(s, "PPP")} · ${format(s, "p")} – ${format(new Date(occ.endMs), "p")}`;
}

export function CalendarEventInspector({ className }: { className?: string }) {
  const {
    occurrences,
    selectedId,
    select,
    statusOptions,
    priorityOptions,
    labelOptions,
    permissions,
    editable,
    can,
    deleteItem,
    applyEditedSubtree,
    editingId,
    openEditor,
    closeEditor,
  } = useCalendar();

  const occ = useMemo(
    () => occurrences.find((o) => o.id === selectedId) ?? null,
    [occurrences, selectedId],
  );

  if (!occ) {
    return (
      <div
        className={cn(
          "flex flex-col items-center justify-center gap-1 p-6 text-center",
          className,
        )}
      >
        <p className="text-sm font-medium text-muted-foreground">
          No event selected
        </p>
        <p className="text-xs text-muted-foreground">
          Click an event to see its details{editable ? " and edit it" : ""}.
        </p>
      </div>
    );
  }

  const item = occ.item;
  const editing = editingId === item.id;
  const status = statusOptions?.find((o) => o.value === item.status);
  const priority = priorityOptions?.find((o) => o.value === item.priority);
  const canEdit = can("editDetails", item);
  const canDelete = can("delete", item);

  return (
    <div className={cn("flex flex-col gap-3 p-3", className)}>
      <div className="flex items-center justify-between gap-2">
        <span className="inline-flex items-center gap-2 text-xs font-medium uppercase tracking-wide text-muted-foreground">
          <span
            className="size-2 rounded-full"
            style={{ background: occ.color.fill }}
            aria-hidden
          />
          Event details
        </span>
        <button
          type="button"
          aria-label="Clear selection"
          onClick={() => select(null)}
          className="rounded-sm p-0.5 text-muted-foreground hover:bg-muted hover:text-foreground"
        >
          <X className="size-4" />
        </button>
      </div>

      {editing ? (
        <EventEditorPanel
          item={item}
          statusOptions={statusOptions}
          priorityOptions={priorityOptions}
          labelOptions={labelOptions}
          permissions={permissions}
          onChange={applyEditedSubtree}
          onDone={closeEditor}
        />
      ) : (
        <>
          <div className="space-y-1">
            <h3 className="text-base font-semibold leading-tight text-foreground">
              {item.name}
            </h3>
            <p className="text-xs text-muted-foreground">{whenLabel(occ)}</p>
          </div>

          <div className="flex flex-wrap gap-1.5">
            {status ? (
              <Badge variant={status.variant ?? "secondary"}>
                {status.label}
              </Badge>
            ) : null}
            {priority ? (
              <Badge
                variant="outline"
                style={
                  priority.color
                    ? { color: priority.color, borderColor: priority.color }
                    : undefined
                }
              >
                {priority.label}
              </Badge>
            ) : null}
            {occ.overdue ? <Badge variant="destructive">Overdue</Badge> : null}
          </div>

          {item.description ? (
            <p className="whitespace-pre-wrap text-sm leading-relaxed text-foreground/80">
              {item.description}
            </p>
          ) : null}

          {editable ? (
            <div className="mt-1 flex gap-2">
              <Button
                size="sm"
                className="gap-1.5"
                disabled={!canEdit}
                onClick={() => openEditor(item.id)}
              >
                <Pencil className="size-3.5" /> Edit
              </Button>
              <Button
                size="sm"
                variant="outline"
                className="gap-1.5"
                disabled={!canDelete}
                onClick={() => {
                  deleteItem(item.id);
                  select(null);
                }}
              >
                <Trash2 className="size-3.5" /> Delete
              </Button>
            </div>
          ) : null}
        </>
      )}
    </div>
  );
}

"use client";

/**
 * Editing overlays (Tier B) mounted by the assembly alongside the quick-composer:
 *
 *  - `CalendarEventEditorOverlay` — the detail editor on `editingId`. Stage 1–3
 *    only rendered the editor inside the optional `CalendarEventInspector`, so the
 *    context-menu "Edit…" + keyboard Enter were dead in the default assembly. This
 *    surfaces the SAME editor without the inspector. The assembly mounts it only
 *    when `showInspector` is false (the inspector hosts it inline → no double).
 *  - `CalendarRenameField` — inline rename on `renamingId` (the `beginRename`
 *    target was declared in Stage 1–3 but never rendered → F2 / menu-Rename were
 *    dead). A small title-input popup.
 *
 * Both use the same centered modal shell as gantt's `GanttEditPopover` — a plain
 * backdrop button + panel (NOT the shadcn `dialog`/`popover` primitive), so the
 * task family stays consistent and it sidesteps the Radix/Base-UI `asChild`
 * divergence the v1 tooltip avoided the same way. Backdrop click + Esc close.
 * `EventEditorPanel` is the shared, prop-driven editor block reused by the
 * inspector so the lazy `<TodoRichCard>` boundary is defined once.
 */

import { lazy, Suspense, useEffect, useRef } from "react";
import type { ReactNode } from "react";
import { Check } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { cn } from "@/lib/utils";
import { useCalendar } from "../hooks/use-calendar-context";
import type {
  TodoItem,
  TodoLabelOption,
  TodoPermissions,
  TodoPriorityOption,
  TodoStatusOption,
} from "../types";

const LazyTodoRichCard = lazy(() =>
  import("../../todo-rich-card").then((m) => ({ default: m.TodoRichCard })),
);

/**
 * Shared editor block (Tier C) — the lazy `<TodoRichCard editable>` + a Done
 * button. Prop-driven (zero context); used inline by the inspector AND by the
 * centered editor overlay.
 */
export function EventEditorPanel({
  item,
  statusOptions,
  priorityOptions,
  labelOptions,
  permissions,
  onChange,
  onDone,
  className,
}: {
  item: TodoItem;
  statusOptions?: TodoStatusOption[];
  priorityOptions?: TodoPriorityOption[];
  labelOptions?: TodoLabelOption[];
  permissions?: TodoPermissions;
  onChange: (next: TodoItem) => void;
  onDone: () => void;
  className?: string;
}) {
  return (
    <div className={cn("flex flex-col gap-2", className)}>
      <Suspense
        fallback={
          <div className="rounded-lg border border-border bg-card p-6 text-center text-sm text-muted-foreground">
            Loading editor…
          </div>
        }
      >
        <LazyTodoRichCard
          value={item}
          editable
          statusOptions={statusOptions}
          priorityOptions={priorityOptions}
          labelOptions={labelOptions}
          permissions={permissions}
          onChange={(tree) => onChange(tree)}
        />
      </Suspense>
      <Button
        size="sm"
        variant="secondary"
        className="gap-1.5 self-end"
        onClick={onDone}
      >
        <Check className="size-3.5" /> Done editing
      </Button>
    </div>
  );
}

/**
 * Centered modal shell — a labelled backdrop button + a panel on top. Mirrors
 * `GanttEditPopover` (no shadcn `dialog`/`popover`; backdrop + Esc close).
 */
function OverlayShell({
  label,
  onClose,
  className,
  children,
}: {
  label: string;
  onClose: () => void;
  className?: string;
  children: ReactNode;
}) {
  const contentRef = useRef<HTMLDivElement>(null);
  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if (e.key === "Escape") onClose();
    };
    window.addEventListener("keydown", onKey);
    // Move focus into the dialog on open so keyboard / screen-reader users land
    // inside it (a more specific control, e.g. the rename input, may refocus after).
    const raf = requestAnimationFrame(() => contentRef.current?.focus());
    return () => {
      window.removeEventListener("keydown", onKey);
      cancelAnimationFrame(raf);
    };
  }, [onClose]);
  return (
    <div
      role="dialog"
      aria-modal="true"
      aria-label={label}
      className="fixed inset-0 z-50 flex items-center justify-center p-4"
    >
      <button
        type="button"
        aria-label="Close"
        onClick={onClose}
        className="absolute inset-0 cursor-default bg-background/70 backdrop-blur-sm"
      />
      <div
        ref={contentRef}
        tabIndex={-1}
        className={cn("relative z-10 w-full max-w-sm outline-none", className)}
      >
        {children}
      </div>
    </div>
  );
}

/**
 * Centered detail-editor overlay (Tier B). Renders the shared editor on
 * `editingId` without requiring the inspector. Mounted by the assembly only when
 * `showInspector` is false.
 */
export function CalendarEventEditorOverlay() {
  const {
    occurrences,
    statusOptions,
    priorityOptions,
    labelOptions,
    permissions,
    editingId,
    applyEditedSubtree,
    closeEditor,
  } = useCalendar();
  const item = editingId
    ? (occurrences.find((o) => o.id === editingId)?.item ?? null)
    : null;

  if (!editingId || !item) return null;

  return (
    <OverlayShell
      label={`Edit ${item.name}`}
      onClose={closeEditor}
      className="max-h-[85vh] overflow-auto"
    >
      <EventEditorPanel
        item={item}
        statusOptions={statusOptions}
        priorityOptions={priorityOptions}
        labelOptions={labelOptions}
        permissions={permissions}
        onChange={applyEditedSubtree}
        onDone={closeEditor}
      />
    </OverlayShell>
  );
}

/**
 * Inline-rename popup (Tier B). Renders on `renamingId` — a title input prefilled
 * from the item. Enter commits, Esc / Cancel / backdrop aborts.
 */
export function CalendarRenameField() {
  const { occurrences, renamingId, renameItemAction, endRename } = useCalendar();
  const item = renamingId
    ? (occurrences.find((o) => o.id === renamingId)?.item ?? null)
    : null;
  const inputRef = useRef<HTMLInputElement>(null);

  // Focus + select on open (rAF so the input is mounted; not a render-time read).
  useEffect(() => {
    if (!renamingId) return;
    const raf = requestAnimationFrame(() => {
      inputRef.current?.focus();
      inputRef.current?.select();
    });
    return () => cancelAnimationFrame(raf);
  }, [renamingId]);

  if (!renamingId || !item) return null;

  const commit = () => {
    const value = inputRef.current?.value.trim();
    if (value) renameItemAction(renamingId, value);
    endRename();
  };

  return (
    <OverlayShell label={`Rename ${item.name}`} onClose={endRename} className="max-w-xs">
      <div className="rounded-lg border border-border bg-card p-3 shadow-lg">
        <label
          htmlFor="cal-rename-input"
          className="mb-1.5 block text-xs font-medium text-muted-foreground"
        >
          Rename event
        </label>
        <Input
          id="cal-rename-input"
          key={renamingId}
          ref={inputRef}
          defaultValue={item.name}
          onKeyDown={(e) => {
            if (e.key === "Enter") {
              e.preventDefault();
              commit();
            } else if (e.key === "Escape") {
              e.preventDefault();
              endRename();
            }
          }}
        />
        <div className="mt-2 flex justify-end gap-2">
          <Button size="sm" variant="ghost" onClick={() => endRename()}>
            Cancel
          </Button>
          <Button size="sm" onClick={commit}>
            Save
          </Button>
        </div>
      </div>
    </OverlayShell>
  );
}

